"""
Parameterized generator for GH906_ray_29102.

Source PR:    https://github.com/ray-project/ray/pull/29102
Source Issue: https://github.com/ray-project/ray/issues/1234

Seed varies: renames 'above' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH906_ray_29102'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH906_ray_29102'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('above', 'above' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH906_ray_29102',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'ray-project/ray',
                "pr_number": 29102,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/ray-project/ray/pull/29102",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'python/ray/tune/examples/pb2_example.py': '#!/usr/bin/env python\n\nimport argparse\n\nimport ray\nfrom ray import air, tune\nfrom ray.tune.schedulers.pb2 import PB2\nfrom ray.tune.examples.pbt_function import pbt_function\n\nif __name__ == "__main__":\n    parser = argparse.ArgumentParser()\n    parser.add_argument(\n        "--smoke-test", action="store_true", help="Finish quickly for testing"\n    )\n    parser.add_argument(\n        "--server-address",\n        type=str,\n        default=None,\n        required=False,\n        help="The address of server to connect to if using Ray Client.",\n    )\n    args, _ = parser.parse_known_args()\n    if args.smoke_test:\n        ray.init(num_cpus=2)  # force pausing to happen for test\n    else:\n        if args.server_address:\n            ray.init(f"ray://{args.server_address}")\n        else:\n            ray.init()\n\n    pbt = PB2(\n        perturbation_interval=20,\n        hyperparam_bounds={\n            # hyperparameter bounds.\n            "lr": [0.0001, 0.02],\n        },\n    )\n\n    tuner = tune.Tuner(\n        pbt_function,\n        run_config=air.RunConfig(\n            name="pbt_test",\n            verbose=False,\n            stop={\n                "training_iteration": 30,\n            },\n            failure_config=air.FailureConfig(\n                fail_fast=True,\n            ),\n        ),\n        tune_config=tune.TuneConfig(\n            scheduler=pbt,\n            metric="mean_accuracy",\n            mode="max",\n            num_samples=8,\n        ),\n        param_space={\n            "lr": 0.0001,\n            # note: this parameter is perturbed but has no effect on\n            # the model training in this example\n            "some_other_factor": 1,\n        },\n    )\n    results = tuner.fit()\n\n    print("Best hyperparameters found were: ", results.get_best_result().config)\n',
            'python/ray/tune/examples/pbt_function.py': '#!/usr/bin/env python\n\nimport numpy as np\nimport argparse\nimport random\n\nimport ray\nfrom ray import air, tune\nfrom ray.air import session\nfrom ray.air.checkpoint import Checkpoint\nfrom ray.tune.schedulers import PopulationBasedTraining\n\n\ndef pbt_function(config):\n    """Toy PBT problem for benchmarking adaptive learning rate.\n\n    The goal is to optimize this trainable\'s accuracy. The accuracy increases\n    fastest at the optimal lr, which is a function of the current accuracy.\n\n    The optimal lr schedule for this problem is the triangle wave as follows.\n    Note that many lr schedules for real models also follow this shape:\n\n     best lr\n      ^\n      |    /\\\n      |   /  \\\n      |  /    \\\n      | /      \\\n      ------------> accuracy\n\n    In this problem, using PBT with a population of 2-4 is sufficient to\n    roughly approximate this lr schedule. Higher population sizes will yield\n    faster convergence. Training will not converge without PBT.\n    """\n    lr = config["lr"]\n    accuracy = 0.0  # end = 1000\n    start = 0\n    if session.get_checkpoint():\n        state = session.get_checkpoint().to_dict()\n        accuracy = state["acc"]\n        start = state["step"]\n\n    midpoint = 100  # lr starts decreasing after acc > midpoint\n    q_tolerance = 3  # penalize exceeding lr by more than this multiple\n    noise_level = 2  # add gaussian noise to the acc increase\n    # triangle wave:\n    #  - start at 0.001 @ t=0,\n    #  - peak at 0.01 @ t=midpoint,\n    #  - end at 0.001 @ t=midpoint * 2,\n    for step in range(start, 100):\n        if accuracy < midpoint:\n            optimal_lr = 0.01 * accuracy / midpoint\n        else:\n            optimal_lr = 0.01 - 0.01 * (accuracy - midpoint) / midpoint\n        optimal_lr = min(0.01, max(0.001, optimal_lr))\n\n        # compute accuracy increase\n        q_err = max(lr, optimal_lr) / min(lr, optimal_lr)\n        if q_err < q_tolerance:\n            accuracy += (1.0 / q_err) * random.random()\n        elif lr > optimal_lr:\n            accuracy -= (q_err - q_tolerance) * random.random()\n        accuracy += noise_level * np.random.normal()\n        accuracy = max(0, accuracy)\n\n        checkpoint = None\n        if step % 3 == 0:\n            checkpoint = Checkpoint.from_dict({"acc": accuracy, "step": start})\n\n        session.report(\n            {\n                "mean_accuracy": accuracy,\n                "cur_lr": lr,\n                "optimal_lr": optimal_lr,  # for debugging\n                "q_err": q_err,  # for debugging\n                "done": accuracy > midpoint * 2,  # this stops the training process\n            },\n            checkpoint=checkpoint,\n        )\n\n\ndef run_tune_pbt():\n    pbt = PopulationBasedTraining(\n        time_attr="training_iteration",\n        perturbation_interval=4,\n        hyperparam_mutations={\n            # distribution for resampling\n            "lr": lambda: random.uniform(0.0001, 0.02),\n            # allow perturbations within this set of categorical values\n            "some_other_factor": [1, 2],\n        },\n    )\n\n    tuner = tune.Tuner(\n        pbt_function,\n        run_config=air.RunConfig(\n            name="pbt_test",\n            verbose=False,\n            stop={\n                "training_iteration": 30,\n            },\n            failure_config=air.FailureConfig(\n                fail_fast=True,\n            ),\n        ),\n        tune_config=tune.TuneConfig(\n            scheduler=pbt,\n            metric="mean_accuracy",\n            mode="max",\n            num_samples=8,\n        ),\n        param_space={\n            "lr": 0.0001,\n            # note: this parameter is perturbed but has no effect on\n            # the model training in this example\n            "some_other_factor": 1,\n        },\n    )\n    results = tuner.fit()\n\n    print("Best hyperparameters found were: ", results.get_best_result().config)\n\n\nif __name__ == "__main__":\n    parser = argparse.ArgumentParser()\n    parser.add_argument(\n        "--smoke-test", action="store_true", help="Finish quickly for testing"\n    )\n    parser.add_argument(\n        "--server-address",\n        type=str,\n        default=None,\n        required=False,\n        help="The address of server to connect to if using Ray Client.",\n    )\n    args, _ = parser.parse_known_args()\n    if args.smoke_test:\n        ray.init(num_cpus=2)  # force pausing to happen for test\n    else:\n        if args.server_address is not None:\n            ray.init(f"ray://{args.server_address}")\n        else:\n            ray.init()\n\n    run_tune_pbt()\n',
            'python/ray/tune/schedulers/pb2.py': 'from typing import Dict, Optional\nfrom copy import deepcopy\nimport logging\nimport numpy as np\nimport pandas as pd\n\nfrom ray.tune import TuneError\nfrom ray.tune.schedulers import PopulationBasedTraining\n\n\ndef import_pb2_dependencies():\n    try:\n        import GPy\n    except ImportError:\n        GPy = None\n    try:\n        import sklearn\n    except ImportError:\n        sklearn = None\n    return GPy, sklearn\n\n\nGPy, has_sklearn = import_pb2_dependencies()\n\nif GPy and has_sklearn:\n    from ray.tune.schedulers.pb2_utils import (\n        normalize,\n        optimize_acq,\n        select_length,\n        UCB,\n        standardize,\n        TV_SquaredExp,\n    )\n\nlogger = logging.getLogger(__name__)\n\n\ndef select_config(\n    Xraw: np.array,\n    yraw: np.array,\n    current: list,\n    newpoint: np.array,\n    bounds: dict,\n    num_f: int,\n):\n    """Selects the next hyperparameter config to try.\n\n    This function takes the formatted data, fits the GP model and optimizes the\n    UCB acquisition function to select the next point.\n\n    Args:\n        Xraw: The un-normalized array of hyperparams, Time and\n            Reward\n        yraw: The un-normalized vector of reward changes.\n        current: The hyperparams of trials currently running. This is\n            important so we do not select the same config twice. If there is\n            data here then we fit a second GP including it\n            (with fake y labels). The GP variance doesn\'t depend on the y\n            labels so it is ok.\n        newpoint: The Reward and Time for the new point.\n            We cannot change these as they are based on the *new weights*.\n        bounds: Bounds for the hyperparameters. Used to normalize.\n        num_f: The number of fixed params. Almost always 2 (reward+time)\n\n    Return:\n        xt: A vector of new hyperparameters.\n    """\n    length = select_length(Xraw, yraw, bounds, num_f)\n\n    Xraw = Xraw[-length:, :]\n    yraw = yraw[-length:]\n\n    base_vals = np.array(list(bounds.values())).T\n    oldpoints = Xraw[:, :num_f]\n    old_lims = np.concatenate(\n        (np.max(oldpoints, axis=0), np.min(oldpoints, axis=0))\n    ).reshape(2, oldpoints.shape[1])\n    limits = np.concatenate((old_lims, base_vals), axis=1)\n\n    X = normalize(Xraw, limits)\n    y = standardize(yraw).reshape(yraw.size, 1)\n\n    fixed = normalize(newpoint, oldpoints)\n\n    kernel = TV_SquaredExp(\n        input_dim=X.shape[1], variance=1.0, lengthscale=1.0, epsilon=0.1\n    )\n\n    try:\n        m = GPy.models.GPRegression(X, y, kernel)\n    except np.linalg.LinAlgError:\n        # add diagonal ** we would ideally make this something more robust...\n        X += np.eye(X.shape[0]) * 1e-3\n        m = GPy.models.GPRegression(X, y, kernel)\n\n    try:\n        m.optimize()\n    except np.linalg.LinAlgError:\n        # add diagonal ** we would ideally make this something more robust...\n        X += np.eye(X.shape[0]) * 1e-3\n        m = GPy.models.GPRegression(X, y, kernel)\n        m.optimize()\n\n    m.kern.lengthscale.fix(m.kern.lengthscale.clip(1e-5, 1))\n\n    if current is None:\n        m1 = deepcopy(m)\n    else:\n        # add the current trials to the dataset\n        padding = np.array([fixed for _ in range(current.shape[0])])\n        current = normalize(current, base_vals)\n        current = np.hstack((padding, current))\n\n        Xnew = np.vstack((X, current))\n        ypad = np.zeros(current.shape[0])\n        ypad = ypad.reshape(-1, 1)\n        ynew = np.vstack((y, ypad))\n\n        # kernel = GPy.kern.RBF(input_dim=X.shape[1], variance=1.,\n        # lengthscale=1.)\n        kernel = TV_SquaredExp(\n            input_dim=X.shape[1], variance=1.0, lengthscale=1.0, epsilon=0.1\n        )\n        m1 = GPy.models.GPRegression(Xnew, ynew, kernel)\n        m1.optimize()\n\n    xt = optimize_acq(UCB, m, m1, fixed, num_f)\n\n    # convert back...\n    xt = xt * (np.max(base_vals, axis=0) - np.min(base_vals, axis=0)) + np.min(\n        base_vals, axis=0\n    )\n\n    xt = xt.astype(np.float32)\n    return xt\n\n\ndef explore(data, bounds, current, base, old, config):\n    """Returns next hyperparameter configuration to use.\n\n    This function primarily processes the data from completed trials\n    and then requests the next config from the select_config function.\n    It then adds the new trial to the dataframe, so that the reward change\n    can be computed using the new weights.\n    It returns the new point and the dataframe with the new entry.\n    """\n\n    df = data.sort_values(by="Time").reset_index(drop=True)\n\n    # Group by trial ID and hyperparams.\n    # Compute change in timesteps and reward.\n    df["y"] = df.groupby(["Trial"] + list(bounds.keys()))["Reward"].diff()\n    df["t_change"] = df.groupby(["Trial"] + list(bounds.keys()))["Time"].diff()\n\n    # Delete entries without positive change in t.\n    df = df[df["t_change"] > 0].reset_index(drop=True)\n    df["R_before"] = df.Reward - df.y\n\n    # Normalize the reward change by the update size.\n    # For example if trials took diff lengths of time.\n    df["y"] = df.y / df.t_change\n    df = df[~df.y.isna()].reset_index(drop=True)\n    df = df.sort_values(by="Time").reset_index(drop=True)\n\n    # Only use the last 1k datapoints, so the GP is not too slow.\n    df = df.iloc[-1000:, :].reset_index(drop=True)\n\n    # We need this to know the T and Reward for the weights.\n    dfnewpoint = df[df["Trial"] == str(base)]\n\n    if not dfnewpoint.empty:\n        # N ow specify the dataset for the GP.\n        y = np.array(df.y.values)\n        # Meta data we keep -> episodes and reward.\n        # (TODO: convert to curve)\n        t_r = df[["Time", "R_before"]]\n        hparams = df[bounds.keys()]\n        X = pd.concat([t_r, hparams], axis=1).values\n        newpoint = df[df["Trial"] == str(base)].iloc[-1, :][["Time", "R_before"]].values\n        new = select_config(X, y, current, newpoint, bounds, num_f=len(t_r.columns))\n\n        new_config = config.copy()\n        values = []\n        for i, col in enumerate(hparams.columns):\n            if isinstance(config[col], int):\n                new_config[col] = int(new[i])\n                values.append(int(new[i]))\n            else:\n                new_config[col] = new[i]\n                values.append(new[i])\n\n        new_T = df[df["Trial"] == str(base)].iloc[-1, :]["Time"]\n        new_Reward = df[df["Trial"] == str(base)].iloc[-1, :].Reward\n\n        lst = [[old] + [new_T] + values + [new_Reward]]\n        cols = ["Trial", "Time"] + list(bounds) + ["Reward"]\n        new_entry = pd.DataFrame(lst, columns=cols)\n\n        # Create an entry for the new config, with the reward from the\n        # copied agent.\n        data = pd.concat([data, new_entry]).reset_index(drop=True)\n\n    else:\n        new_config = config.copy()\n\n    return new_config, data\n\n\nclass PB2(PopulationBasedTraining):\n    """Implements the Population Based Bandit (PB2) algorithm.\n\n    PB2 trains a group of models (or agents) in parallel. Periodically, poorly\n    performing models clone the state of the top performers, and the hyper-\n    parameters are re-selected using GP-bandit optimization. The GP model is\n    trained to predict the improvement in the next training period.\n\n    Like PBT, PB2 adapts hyperparameters during training time. This enables\n    very fast hyperparameter discovery and also automatically discovers\n    schedules.\n\n    This Tune PB2 implementation is built on top of Tune\'s PBT implementation.\n    It considers all trials added as part of the PB2 population. If the number\n    of trials exceeds the cluster capacity, they will be time-multiplexed as to\n    balance training progress across the population. To run multiple trials,\n    use `tune.TuneConfig(num_samples=<int>)`.\n\n    In {LOG_DIR}/{MY_EXPERIMENT_NAME}/, all mutations are logged in\n    `pb2_global.txt` and individual policy perturbations are recorded\n    in pb2_policy_{i}.txt. Tune logs: [target trial tag, clone trial tag,\n    target trial iteration, clone trial iteration, old config, new config]\n    on each perturbation step.\n\n    Args:\n        time_attr: The training result attr to use for comparing time.\n            Note that you can pass in something non-temporal such as\n            `training_iteration` as a measure of progress, the only requirement\n            is that the attribute should increase monotonically.\n        metric: The training result objective value attribute. Stopping\n            procedures will use this attribute.\n        mode: One of {min, max}. Determines whether objective is\n            minimizing or maximizing the metric attribute.\n        perturbation_interval: Models will be considered for\n            perturbation at this interval of `time_attr`. Note that\n            perturbation incurs checkpoint overhead, so you shouldn\'t set this\n            to be too frequent.\n        hyperparam_bounds: Hyperparameters to mutate. The format is\n            as follows: for each key, enter a list of the form [min, max]\n            representing the minimum and maximum possible hyperparam values.\n        quantile_fraction: Parameters are transferred from the top\n            `quantile_fraction` fraction of trials to the bottom\n            `quantile_fraction` fraction. Needs to be between 0 and 0.5.\n            Setting it to 0 essentially implies doing no exploitation at all.\n        log_config: Whether to log the ray config of each model to\n            local_dir at each exploit. Allows config schedule to be\n            reconstructed.\n        require_attrs: Whether to require time_attr and metric to appear\n            in result for every iteration. If True, error will be raised\n            if these values are not present in trial result.\n        synch: If False, will use asynchronous implementation of\n            PBT. Trial perturbations occur every perturbation_interval for each\n            trial independently. If True, will use synchronous implementation\n            of PBT. Perturbations will occur only after all trials are\n            synced at the same time_attr every perturbation_interval.\n            Defaults to False. See Appendix A.1 here\n            https://arxiv.org/pdf/1711.09846.pdf.\n\n    Example:\n        >>> from ray import tune\n        >>> from ray.tune.schedulers.pb2 import PB2\n        >>> from ray.tune.examples.pbt_function import pbt_function\n        >>> # run "pip install gpy" to use PB2\n        >>> pb2 = PB2( # doctest: +SKIP\n        ...     metric="mean_accuracy",\n        ...     mode="max",\n        ...     perturbation_interval=20,\n        ...     hyperparam_bounds={\n        ...     "factor": [0.0, 20.0],\n        ... })\n        >>> tuner = tune.Tuner(  # doctest: +SKIP\n        ...     pbt_function,\n        ...     tune_config=tune.TuneConfig(\n        ...         scheduler=pb2,\n        ...         num_samples=8,\n        ...     ),\n        ...     param_space={"lr": 0.0001}\n        ... )\n        >>> tuner.fit()  # doctest: +SKIP\n\n    """\n\n    def __init__(\n        self,\n        time_attr: str = "time_total_s",\n        metric: Optional[str] = None,\n        mode: Optional[str] = None,\n        perturbation_interval: float = 60.0,\n        hyperparam_bounds: Dict = None,\n        quantile_fraction: float = 0.25,\n        log_config: bool = True,\n        require_attrs: bool = True,\n        synch: bool = False,\n    ):\n\n        gpy_available, sklearn_available = import_pb2_dependencies()\n        if not gpy_available:\n            raise RuntimeError("Please install GPy to use PB2.")\n\n        if not sklearn_available:\n            raise RuntimeError("Please install scikit-learn to use PB2.")\n\n        hyperparam_bounds = hyperparam_bounds or {}\n        for value in hyperparam_bounds.values():\n            if not isinstance(value, (list, tuple)) or len(value) != 2:\n                raise ValueError(\n                    "`hyperparam_bounds` values must either be "\n                    "a list or tuple of size 2, but got {} "\n                    "instead".format(value)\n                )\n\n        if not hyperparam_bounds:\n            raise TuneError(\n                "`hyperparam_bounds` must be specified to use PB2 scheduler."\n            )\n\n        super(PB2, self).__init__(\n            time_attr=time_attr,\n            metric=metric,\n            mode=mode,\n            perturbation_interval=perturbation_interval,\n            hyperparam_mutations=hyperparam_bounds,\n            quantile_fraction=quantile_fraction,\n            resample_probability=0,\n            custom_explore_fn=explore,\n            log_config=log_config,\n            require_attrs=require_attrs,\n            synch=synch,\n        )\n\n        self.last_exploration_time = 0  # when we last explored\n        self.data = pd.DataFrame()\n\n        self._hyperparam_bounds = hyperparam_bounds\n\n        # Current = trials running that have already re-started after reaching\n        #           the checkpoint. When exploring we care if these trials\n        #           are already in or scheduled to be in the next round.\n        self.current = None\n\n    def _save_trial_state(self, state, time, result, trial):\n\n        score = super(PB2, self)._save_trial_state(state, time, result, trial)\n\n        # Data logging for PB2.\n\n        # Collect hyperparams names and current values for this trial.\n        names = []\n        values = []\n        for key in self._hyperparam_bounds:\n            names.append(str(key))\n            values.append(trial.config[key])\n\n        # Store trial state and hyperparams in dataframe.\n        # this needs to be made more general.\n        lst = [[trial, result[self._time_attr]] + values + [score]]\n        cols = ["Trial", "Time"] + names + ["Reward"]\n        entry = pd.DataFrame(lst, columns=cols)\n\n        self.data = pd.concat([self.data, entry]).reset_index(drop=True)\n        self.data.Trial = self.data.Trial.astype("str")\n\n    def _get_new_config(self, trial, trial_to_clone):\n        # If we are at a new timestep, we dont want to penalise for trials\n        # still going.\n        if self.data["Time"].max() > self.last_exploration_time:\n            self.current = None\n\n        new_config, data = explore(\n            self.data,\n            self._hyperparam_bounds,\n            self.current,\n            trial_to_clone,\n            trial,\n            trial_to_clone.config,\n        )\n\n        # Important to replace the old values, since we are copying across\n        self.data = data.copy()\n\n        # If the current guy being selecting is at a point that is already\n        # done, then append the data to the "current" which contains the\n        # points in the current batch.\n        new = [new_config[key] for key in self._hyperparam_bounds]\n\n        new = np.array(new)\n        new = new.reshape(1, new.size)\n        if self.data["Time"].max() > self.last_exploration_time:\n            self.last_exploration_time = self.data["Time"].max()\n            self.current = new.copy()\n        else:\n            self.current = np.concatenate((self.current, new), axis=0)\n            logger.debug(self.current)\n\n        return new_config\n',
            'python/ray/tune/schedulers/pbt.py': 'import copy\nimport json\nimport logging\nimport math\nimport os\nimport random\nimport shutil\nfrom typing import Callable, Dict, List, Optional, Tuple, Union\n\nfrom ray.air._internal.checkpoint_manager import CheckpointStorage\nfrom ray.tune.execution import trial_runner\nfrom ray.tune.error import TuneError\nfrom ray.tune.result import DEFAULT_METRIC, TRAINING_ITERATION\nfrom ray.tune.search import SearchGenerator\nfrom ray.tune.utils.util import SafeFallbackEncoder\nfrom ray.tune.search.sample import Domain, Function\nfrom ray.tune.schedulers import FIFOScheduler, TrialScheduler\nfrom ray.tune.search.variant_generator import format_vars\nfrom ray.tune.experiment import Trial\nfrom ray.util import PublicAPI\nfrom ray.util.debug import log_once\n\nlogger = logging.getLogger(__name__)\n\n\nclass _PBTTrialState:\n    """Internal PBT state tracked per-trial."""\n\n    def __init__(self, trial: Trial):\n        self.orig_tag = trial.experiment_tag\n        self.last_score = None\n        self.last_checkpoint = None\n        self.last_perturbation_time = 0\n        self.last_train_time = 0  # Used for synchronous mode.\n        self.last_result = None  # Used for synchronous mode.\n\n    def __repr__(self) -> str:\n        return str(\n            (\n                self.last_score,\n                self.last_checkpoint,\n                self.last_train_time,\n                self.last_perturbation_time,\n            )\n        )\n\n\ndef _explore(\n    config: Dict,\n    mutations: Dict,\n    resample_probability: float,\n    perturbation_factors: Tuple[float],\n    custom_explore_fn: Optional[Callable],\n) -> Tuple[Dict, Dict]:\n    """Return a perturbed config and string descriptors of the operations performed\n    on the original config to produce the new config.\n\n    Args:\n        config: Original hyperparameter configuration.\n        mutations: Specification of mutations to perform as documented\n            in the PopulationBasedTraining scheduler.\n        resample_probability: Probability of allowing resampling of a\n            particular variable.\n        perturbation_factors: Scaling factors to choose between when mutating\n            a continuous hyperparameter.\n        custom_explore_fn: Custom explore fn applied after built-in\n            config perturbations are.\n\n    Returns:\n        new_config: New hyperparameter configuration (after random mutations).\n        operations: Map of hyperparam -> string describing mutation operation performed\n    """\n    operations = {}\n    new_config = copy.deepcopy(config)\n    for key, distribution in mutations.items():\n        if isinstance(distribution, dict):\n            # Handle nested hyperparameter configs by recursively perturbing them\n            nested_new_config, nested_ops = _explore(\n                config[key],\n                mutations[key],\n                resample_probability,\n                perturbation_factors,\n                custom_explore_fn=None,\n            )\n            new_config.update({key: nested_new_config})\n            operations.update({key: nested_ops})\n        elif isinstance(distribution, (list, tuple)):\n            # Case 1: Hyperparameter resample distribution is a list/tuple\n            if (\n                random.random() < resample_probability\n                or config[key] not in distribution\n            ):\n                # Resample a value from the list with `resample_probability`\n                new_config[key] = random.choice(distribution)\n                operations[key] = "resample"\n            else:\n                # Otherwise, perturb by shifting to the left or right of the list\n                shift = random.choice([-1, 1])\n                old_idx = distribution.index(config[key])\n                new_idx = old_idx + shift\n                new_idx = min(max(new_idx, 0), len(distribution) - 1)\n                new_config[key] = distribution[new_idx]\n                operations[key] = (\n                    f"shift {\'left\' if shift == -1 else \'right\'}"\n                    f"{\' (noop)\' if old_idx == new_idx else \'\'}"\n                )\n        elif isinstance(distribution, (Domain, Callable)):\n            # Case 2: Hyperparameter resample distribution is:\n            # 1. a function (ex: lambda: np.random.uniform(0, 1))\n            # 2. tune search Domain (ex: tune.uniform(0, 1))\n            if random.random() < resample_probability:\n                # Resample a value from the function/domain with `resample_probability`\n                new_config[key] = (\n                    distribution.sample(None)\n                    if isinstance(distribution, Domain)\n                    else distribution()\n                )\n                operations[key] = "resample"\n            else:\n                # Otherwise, perturb by multiplying the hyperparameter by one\n                # of the `perturbation_factors`\n                perturbation_factor = random.choice(perturbation_factors)\n                new_config[key] = config[key] * perturbation_factor\n                operations[key] = f"* {perturbation_factor}"\n            if isinstance(config[key], int):\n                # If this hyperparameter started out as an integer (ex: `batch_size`),\n                # convert the new value back\n                new_config[key] = int(new_config[key])\n        else:\n            raise ValueError(\n                f"Unsupported hyperparameter distribution type: {type(distribution)}"\n            )\n    if custom_explore_fn:\n        # The user can perform any additional hyperparameter exploration\n        # via `custom_explore_fn`\n        new_config = custom_explore_fn(new_config)\n        assert new_config is not None, "Custom explore fn failed to return new config"\n    return new_config, operations\n\n\ndef _make_experiment_tag(orig_tag: str, config: Dict, mutations: Dict) -> str:\n    """Appends perturbed params to the trial name to show in the console."""\n\n    resolved_vars = {}\n    for k in mutations.keys():\n        resolved_vars[("config", k)] = config[k]\n    return "{}@perturbed[{}]".format(orig_tag, format_vars(resolved_vars))\n\n\ndef _fill_config(\n    config: Dict, attr: str, search_space: Union[dict, list, tuple, Callable, Domain]\n):\n    """Add attr to config by sampling from search_space.\n\n    This is a helper used to set initial hyperparameter values if the user doesn\'t\n    specify them in the Tuner `param_space`.\n    """\n    if isinstance(search_space, Callable):\n        config[attr] = search_space()\n    elif isinstance(search_space, Domain):\n        config[attr] = search_space.sample(None)\n    elif isinstance(search_space, (list, tuple)):\n        config[attr] = random.choice(search_space)\n    elif isinstance(search_space, dict):\n        config[attr] = {}\n        for k, v in search_space.items():\n            _fill_config(config[attr], k, v)\n\n\n@PublicAPI\nclass PopulationBasedTraining(FIFOScheduler):\n    """Implements the Population Based Training (PBT) algorithm.\n\n    https://www.deepmind.com/blog/population-based-training-of-neural-networks\n\n    PBT trains a group of models (or agents) in parallel. Periodically, poorly\n    performing models clone the state of the top performers, and a random\n    mutation is applied to their hyperparameters in the hopes of\n    outperforming the current top models.\n\n    Unlike other hyperparameter search algorithms, PBT mutates hyperparameters\n    during training time. This enables very fast hyperparameter discovery and\n    also automatically discovers good annealing schedules.\n\n    This Tune PBT implementation considers all trials added as part of the\n    PBT population. If the number of trials exceeds the cluster capacity,\n    they will be time-multiplexed as to balance training progress across the\n    population. To run multiple trials, use `tune.TuneConfig(num_samples=<int>)`.\n\n    In {LOG_DIR}/{MY_EXPERIMENT_NAME}/, all mutations are logged in\n    `pbt_global.txt` and individual policy perturbations are recorded\n    in pbt_policy_{i}.txt. Tune logs: [target trial tag, clone trial tag,\n    target trial iteration, clone trial iteration, old config, new config]\n    on each perturbation step.\n\n    Args:\n        time_attr: The training result attr to use for comparing time.\n            Note that you can pass in something non-temporal such as\n            `training_iteration` as a measure of progress, the only requirement\n            is that the attribute should increase monotonically.\n        metric: The training result objective value attribute. Stopping\n            procedures will use this attribute. If None but a mode was passed,\n            the `ray.tune.result.DEFAULT_METRIC` will be used per default.\n        mode: One of {min, max}. Determines whether objective is\n            minimizing or maximizing the metric attribute.\n        perturbation_interval: Models will be considered for\n            perturbation at this interval of `time_attr`. Note that\n            perturbation incurs checkpoint overhead, so you shouldn\'t set this\n            to be too frequent.\n        burn_in_period: Models will not be considered for\n            perturbation before this interval of `time_attr` has passed. This\n            guarantees that models are trained for at least a certain amount\n            of time or timesteps before being perturbed.\n        hyperparam_mutations: Hyperparams to mutate. The format is\n            as follows: for each key, either a list, function,\n            or a tune search space object (tune.loguniform, tune.uniform,\n            etc.) can be provided. A list specifies an allowed set of\n            categorical values. A function or tune search space object\n            specifies the distribution of a continuous parameter. You must\n            use tune.choice, tune.uniform, tune.loguniform, etc.. Arbitrary\n            tune.sample_from objects are not supported.\n            A key can also hold a dict for nested hyperparameters.\n            You must specify at least one of `hyperparam_mutations` or\n            `custom_explore_fn`.\n            Tune will sample the search space provided by\n            `hyperparam_mutations` for the initial hyperparameter values if the\n            corresponding hyperparameters are not present in a trial\'s initial `config`.\n        quantile_fraction: Parameters are transferred from the top\n            `quantile_fraction` fraction of trials to the bottom\n            `quantile_fraction` fraction. Needs to be between 0 and 0.5.\n            Setting it to 0 essentially implies doing no exploitation at all.\n        resample_probability: The probability of resampling from the\n            original distribution when applying `hyperparam_mutations`. If not\n            resampled, the value will be perturbed by a factor chosen from\n            `perturbation_factors` if continuous, or changed to an adjacent value\n            if discrete.\n        perturbation_factors: Scaling factors to choose between when mutating\n            a continuous hyperparameter.\n        custom_explore_fn: You can also specify a custom exploration\n            function. This function is invoked as `f(config)` after built-in\n            perturbations from `hyperparam_mutations` are applied, and should\n            return `config` updated as needed. You must specify at least one of\n            `hyperparam_mutations` or `custom_explore_fn`.\n        log_config: Whether to log the ray config of each model to\n            local_dir at each exploit. Allows config schedule to be\n            reconstructed.\n        require_attrs: Whether to require time_attr and metric to appear\n            in result for every iteration. If True, error will be raised\n            if these values are not present in trial result.\n        synch: If False, will use asynchronous implementation of\n            PBT. Trial perturbations occur every perturbation_interval for each\n            trial independently. If True, will use synchronous implementation\n            of PBT. Perturbations will occur only after all trials are\n            synced at the same time_attr every perturbation_interval.\n            Defaults to False. See Appendix A.1 here\n            https://arxiv.org/pdf/1711.09846.pdf.\n\n    .. code-block:: python\n\n        import random\n        from ray import tune\n        from ray.tune.schedulers import PopulationBasedTraining\n\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="episode_reward_mean",\n            mode="max",\n            perturbation_interval=10,  # every 10 `time_attr` units\n                                       # (training_iterations in this case)\n            hyperparam_mutations={\n                # Perturb factor1 by scaling it by 0.8 or 1.2. Resampling\n                # resets it to a value sampled from the lambda function.\n                "factor_1": lambda: random.uniform(0.0, 20.0),\n                # Alternatively, use tune search space primitives.\n                # The search space for factor_1 is equivalent to factor_2.\n                "factor_2": tune.uniform(0.0, 20.0),\n                # Perturb factor3 by changing it to an adjacent value, e.g.\n                # 10 -> 1 or 10 -> 100. Resampling will choose at random.\n                "factor_3": [1, 10, 100, 1000, 10000],\n                # Using tune.choice is NOT equivalent to the above.\n                # factor_4 is treated as a continuous hyperparameter.\n                "factor_4": tune.choice([1, 10, 100, 1000, 10000]),\n            })\n        tuner = tune.Tuner(\n            trainable,\n            tune_config=tune.TuneConfig(\n                scheduler=pbt,\n                num_samples=8,\n            ),\n        )\n        tuner.fit()\n\n    """\n\n    def __init__(\n        self,\n        time_attr: str = "time_total_s",\n        metric: Optional[str] = None,\n        mode: Optional[str] = None,\n        perturbation_interval: float = 60.0,\n        burn_in_period: float = 0.0,\n        hyperparam_mutations: Dict[\n            str, Union[dict, list, tuple, Callable, Domain]\n        ] = None,\n        quantile_fraction: float = 0.25,\n        resample_probability: float = 0.25,\n        perturbation_factors: Tuple[float, float] = (1.2, 0.8),\n        custom_explore_fn: Optional[Callable] = None,\n        log_config: bool = True,\n        require_attrs: bool = True,\n        synch: bool = False,\n    ):\n        hyperparam_mutations = hyperparam_mutations or {}\n        for value in hyperparam_mutations.values():\n            if not isinstance(value, (dict, list, tuple, Domain, Callable)):\n                raise TypeError(\n                    "`hyperparam_mutation` values must be either "\n                    "a List, Tuple, Dict, a tune search space object, or "\n                    "a callable."\n                )\n            if isinstance(value, Function):\n                raise ValueError(\n                    "arbitrary tune.sample_from objects are not "\n                    "supported for `hyperparam_mutation` values."\n                    "You must use other built in primitives like"\n                    "tune.uniform, tune.loguniform, etc."\n                )\n\n            if not hyperparam_mutations and not custom_explore_fn:\n                raise TuneError(\n                    "You must specify at least one of `hyperparam_mutations` "\n                    "or `custom_explore_fn` to use PBT."\n                )\n\n        if quantile_fraction > 0.5 or quantile_fraction < 0:\n            raise ValueError(\n                "You must set `quantile_fraction` to a value between 0 and"\n                "0.5. Current value: \'{}\'".format(quantile_fraction)\n            )\n\n        if perturbation_interval <= 0:\n            raise ValueError(\n                "perturbation_interval must be a positive number greater "\n                "than 0. Current value: \'{}\'".format(perturbation_interval)\n            )\n\n        if mode:\n            assert mode in ["min", "max"], "`mode` must be \'min\' or \'max\'."\n\n        FIFOScheduler.__init__(self)\n        self._metric = metric\n        self._mode = mode\n        self._metric_op = None\n        if self._mode == "max":\n            self._metric_op = 1.0\n        elif self._mode == "min":\n            self._metric_op = -1.0\n        self._time_attr = time_attr\n        self._perturbation_interval = perturbation_interval\n        self._burn_in_period = burn_in_period\n        self._hyperparam_mutations = hyperparam_mutations\n        self._quantile_fraction = quantile_fraction\n        self._resample_probability = resample_probability\n        self._perturbation_factors = perturbation_factors\n        self._trial_state = {}\n        self._custom_explore_fn = custom_explore_fn\n        self._log_config = log_config\n        self._require_attrs = require_attrs\n        self._synch = synch\n        self._next_perturbation_sync = max(\n            self._perturbation_interval,\n            self._burn_in_period,\n        )\n\n        # Metrics\n        self._num_checkpoints = 0\n        self._num_perturbations = 0\n\n    def set_search_properties(\n        self, metric: Optional[str], mode: Optional[str], **spec\n    ) -> bool:\n        if self._metric and metric:\n            return False\n        if self._mode and mode:\n            return False\n\n        if metric:\n            self._metric = metric\n        if mode:\n            self._mode = mode\n\n        if self._mode == "max":\n            self._metric_op = 1.0\n        elif self._mode == "min":\n            self._metric_op = -1.0\n\n        if self._metric is None and self._mode:\n            # If only a mode was passed, use anonymous metric\n            self._metric = DEFAULT_METRIC\n\n        return True\n\n    def on_trial_add(self, trial_runner: "trial_runner.TrialRunner", trial: Trial):\n        if trial_runner.search_alg is not None and isinstance(\n            trial_runner.search_alg, SearchGenerator\n        ):\n            raise ValueError(\n                "Search algorithms cannot be used with {} "\n                "schedulers. Please remove {}.".format(\n                    self.__class__.__name__, trial_runner.search_alg\n                )\n            )\n\n        if not self._metric or not self._metric_op:\n            raise ValueError(\n                "{} has been instantiated without a valid `metric` ({}) or "\n                "`mode` ({}) parameter. Either pass these parameters when "\n                "instantiating the scheduler, or pass them as parameters "\n                "to `tune.TuneConfig()`".format(\n                    self.__class__.__name__, self._metric, self._mode\n                )\n            )\n\n        self._trial_state[trial] = _PBTTrialState(trial)\n\n        for attr in self._hyperparam_mutations.keys():\n            if attr not in trial.config:\n                if log_once(attr + "-missing"):\n                    logger.debug(\n                        "Cannot find {} in config. Using search "\n                        "space provided by hyperparam_mutations."\n                    )\n                # Add attr to trial\'s config by sampling search space from\n                # hyperparam_mutations.\n                _fill_config(trial.config, attr, self._hyperparam_mutations[attr])\n                # Make sure this attribute is added to CLI output.\n                trial.evaluated_params[attr] = trial.config[attr]\n\n    def on_trial_result(\n        self, trial_runner: "trial_runner.TrialRunner", trial: Trial, result: Dict\n    ) -> str:\n        if self._time_attr not in result:\n            time_missing_msg = (\n                "Cannot find time_attr {} "\n                "in trial result {}. Make sure that this "\n                "attribute is returned in the "\n                "results of your Trainable.".format(self._time_attr, result)\n            )\n            if self._require_attrs:\n                raise RuntimeError(\n                    time_missing_msg\n                    + "If this error is expected, you can change this to "\n                    "a warning message by "\n                    "setting PBT(require_attrs=False)"\n                )\n            else:\n                if log_once("pbt-time_attr-error"):\n                    logger.warning(time_missing_msg)\n        if self._metric not in result:\n            metric_missing_msg = (\n                "Cannot find metric {} in trial result {}. "\n                "Make sure that this attribute is returned "\n                "in the "\n                "results of your Trainable.".format(self._metric, result)\n            )\n            if self._require_attrs:\n                raise RuntimeError(\n                    metric_missing_msg + "If this error is expected, "\n                    "you can change this to a warning message by "\n                    "setting PBT(require_attrs=False)"\n                )\n            else:\n                if log_once("pbt-metric-error"):\n                    logger.warning(metric_missing_msg)\n\n        if self._metric not in result or self._time_attr not in result:\n            return TrialScheduler.CONTINUE\n\n        time = result[self._time_attr]\n        state = self._trial_state[trial]\n\n        # Continue training if burn-in period has not been reached, yet.\n        if time < self._burn_in_period:\n            return TrialScheduler.CONTINUE\n\n        # Continue training if perturbation interval has not been reached, yet.\n        if time - state.last_perturbation_time < self._perturbation_interval:\n            return TrialScheduler.CONTINUE  # avoid checkpoint overhead\n\n        self._save_trial_state(state, time, result, trial)\n\n        if not self._synch:\n            state.last_perturbation_time = time\n            lower_quantile, upper_quantile = self._quantiles()\n            decision = TrialScheduler.CONTINUE\n            for other_trial in trial_runner.get_trials():\n                if other_trial.status in [Trial.PENDING, Trial.PAUSED]:\n                    decision = TrialScheduler.PAUSE\n                    break\n            self._checkpoint_or_exploit(\n                trial, trial_runner, upper_quantile, lower_quantile\n            )\n            return TrialScheduler.NOOP if trial.status == Trial.PAUSED else decision\n        else:\n            # Synchronous mode.\n            if any(\n                self._trial_state[t].last_train_time < self._next_perturbation_sync\n                and t != trial\n                for t in trial_runner.get_live_trials()\n            ):\n                logger.debug("Pausing trial {}".format(trial))\n            else:\n                # All trials are synced at the same timestep.\n                lower_quantile, upper_quantile = self._quantiles()\n                all_trials = trial_runner.get_trials()\n                not_in_quantile = []\n                for t in all_trials:\n                    if t not in lower_quantile and t not in upper_quantile:\n                        not_in_quantile.append(t)\n                # Move upper quantile trials to beginning and lower quantile\n                # to end. This ensures that checkpointing of strong trials\n                # occurs before exploiting of weaker ones.\n                all_trials = upper_quantile + not_in_quantile + lower_quantile\n                for t in all_trials:\n                    logger.debug("Perturbing Trial {}".format(t))\n                    self._trial_state[t].last_perturbation_time = time\n                    self._checkpoint_or_exploit(\n                        t, trial_runner, upper_quantile, lower_quantile\n                    )\n\n                all_train_times = [\n                    self._trial_state[t].last_train_time\n                    for t in trial_runner.get_trials()\n                ]\n                max_last_train_time = max(all_train_times)\n                self._next_perturbation_sync = max(\n                    self._next_perturbation_sync + self._perturbation_interval,\n                    max_last_train_time,\n                )\n            # In sync mode we should pause all trials once result comes in.\n            # Once a perturbation step happens for all trials, they should\n            # still all be paused.\n            # choose_trial_to_run will then pick the next trial to run out of\n            # the paused trials.\n            return (\n                TrialScheduler.NOOP\n                if trial.status == Trial.PAUSED\n                else TrialScheduler.PAUSE\n            )\n\n    def _save_trial_state(\n        self, state: _PBTTrialState, time: int, result: Dict, trial: Trial\n    ):\n        """Saves necessary trial information when result is received.\n        Args:\n            state: The state object for the trial.\n            time: The current timestep of the trial.\n            result: The trial\'s result dictionary.\n            trial: The trial object.\n        """\n\n        # This trial has reached its perturbation interval.\n        # Record new state in the state object.\n        score = self._metric_op * result[self._metric]\n        state.last_score = score\n        state.last_train_time = time\n        state.last_result = result\n\n        return score\n\n    def _checkpoint_or_exploit(\n        self,\n        trial: Trial,\n        trial_runner: "trial_runner.TrialRunner",\n        upper_quantile: List[Trial],\n        lower_quantile: List[Trial],\n    ):\n        """Checkpoint if in upper quantile, exploits if in lower."""\n        trial_executor = trial_runner.trial_executor\n        state = self._trial_state[trial]\n        if trial in upper_quantile:\n            # The trial last result is only updated after the scheduler\n            # callback. So, we override with the current result.\n            logger.debug("Trial {} is in upper quantile".format(trial))\n            logger.debug("Checkpointing {}".format(trial))\n            if trial.status == Trial.PAUSED:\n                # Paused trial will always have an in-memory checkpoint.\n                state.last_checkpoint = trial.checkpoint\n            else:\n                state.last_checkpoint = trial_executor.save(\n                    trial, CheckpointStorage.MEMORY, result=state.last_result\n                )\n            self._num_checkpoints += 1\n        else:\n            state.last_checkpoint = None  # not a top trial\n\n        if trial in lower_quantile:\n            logger.debug("Trial {} is in lower quantile".format(trial))\n            trial_to_clone = random.choice(upper_quantile)\n            assert trial is not trial_to_clone\n            if not self._trial_state[trial_to_clone].last_checkpoint:\n                logger.info(\n                    "[pbt]: no checkpoint for trial."\n                    " Skip exploit for Trial {}".format(trial)\n                )\n                return\n            self._exploit(trial_runner, trial, trial_to_clone)\n\n    def _log_config_on_step(\n        self,\n        trial_state: _PBTTrialState,\n        new_state: _PBTTrialState,\n        trial: Trial,\n        trial_to_clone: Trial,\n        new_config: Dict,\n    ):\n        """Logs transition during exploit/exploit step.\n\n        For each step, logs: [target trial tag, clone trial tag, target trial\n        iteration, clone trial iteration, old config, new config].\n        """\n        trial_name, trial_to_clone_name = (trial_state.orig_tag, new_state.orig_tag)\n        trial_id = trial.trial_id\n        trial_to_clone_id = trial_to_clone.trial_id\n        trial_path = os.path.join(trial.local_dir, "pbt_policy_" + trial_id + ".txt")\n        trial_to_clone_path = os.path.join(\n            trial_to_clone.local_dir, "pbt_policy_" + trial_to_clone_id + ".txt"\n        )\n        policy = [\n            trial_name,\n            trial_to_clone_name,\n            trial.last_result.get(TRAINING_ITERATION, 0),\n            trial_to_clone.last_result.get(TRAINING_ITERATION, 0),\n            trial_to_clone.config,\n            new_config,\n        ]\n        # Log to global file.\n        with open(os.path.join(trial.local_dir, "pbt_global.txt"), "a+") as f:\n            print(json.dumps(policy, cls=SafeFallbackEncoder), file=f)\n        # Overwrite state in target trial from trial_to_clone.\n        if os.path.exists(trial_to_clone_path):\n            shutil.copyfile(trial_to_clone_path, trial_path)\n        # Log new exploit in target trial log.\n        with open(trial_path, "a+") as f:\n            f.write(json.dumps(policy, cls=SafeFallbackEncoder) + "\\n")\n\n    def _get_new_config(self, trial: Trial, trial_to_clone: Trial) -> Tuple[Dict, Dict]:\n        """Gets new config for trial by exploring trial_to_clone\'s config."""\n        return _explore(\n            trial_to_clone.config,\n            self._hyperparam_mutations,\n            self._resample_probability,\n            self._perturbation_factors,\n            self._custom_explore_fn,\n        )\n\n    def _summarize_hyperparam_changes(\n        self, old_params: Dict, new_params: Dict, operations: Dict, prefix: str = ""\n    ) -> str:\n        """Generates a summary of hyperparameter changes from a PBT "explore" step.\n\n        Args:\n            old_params: Old values of hyperparameters that are perturbed to generate\n                the new config\n            new_params: The newly generated hyperparameter config from PBT exploration\n            operations: Map of hyperparam -> string describing mutation the operation\n                performed on it to generate the value in `new_params`\n            prefix: Helper argument to format nested dict hyperparam configs\n\n        Returns:\n            summary_str: The hyperparameter change summary to print/log.\n        """\n        summary_str = ""\n        if not old_params:\n            return summary_str\n        for param_name in old_params:\n            old_val = old_params[param_name]\n            assert param_name in new_params and param_name in operations, (\n                "`old_params`, `new_params`, and `operations` "\n                f"must all contain the key: \'{param_name}\'\\n"\n                f"old_params.keys() = {old_params.keys()}\\n"\n                f"new_params.keys() = {new_params.keys()}\\n"\n                f"operations.keys() = {operations.keys()}\\n"\n            )\n            new_val = new_params[param_name]\n            summary_str += f"{prefix}{param_name} : "\n            if isinstance(old_val, Dict):\n                # Handle nested hyperparameters by recursively summarizing\n                summary_str += "\\n"\n                summary_str += self._summarize_hyperparam_changes(\n                    old_val, new_val, operations[param_name], prefix=prefix + " " * 4\n                )\n            else:\n                op = operations[param_name]\n                arrow = f"--- ({op}) -->"\n                summary_str += f"{old_val} {arrow} {new_val}\\n"\n        return summary_str\n\n    def _exploit(\n        self,\n        trial_runner: "trial_runner.TrialRunner",\n        trial: Trial,\n        trial_to_clone: Trial,\n    ):\n        """Transfers perturbed state from trial_to_clone -> trial.\n\n        If specified, also logs the updated hyperparam state.\n        """\n        trial_state = self._trial_state[trial]\n        new_state = self._trial_state[trial_to_clone]\n        logger.info(\n            "\\n\\n[PBT] [Exploit] Cloning trial "\n            "{} (score = {:4f}) into trial {} (score = {:4f})\\n".format(\n                trial_to_clone.trial_id,\n                new_state.last_score,\n                trial.trial_id,\n                trial_state.last_score,\n            )\n        )\n\n        new_config, operations = self._get_new_config(trial, trial_to_clone)\n\n        # Only log mutated hyperparameters and not entire config.\n        old_params = {\n            k: v\n            for k, v in trial_to_clone.config.items()\n            if k in self._hyperparam_mutations\n        }\n        new_params = {\n            k: v for k, v in new_config.items() if k in self._hyperparam_mutations\n        }\n        explore_info_str = (\n            "\\n\\n[PBT] [Explore] Perturbed the hyperparameter config of trial"\n            f"{trial.trial_id}:\\n"\n        )\n        explore_info_str += (\n            self._summarize_hyperparam_changes(old_params, new_params, operations)\n            or "No hyperparameters mutated."\n        )\n        logger.info(explore_info_str)\n\n        if self._log_config:\n            self._log_config_on_step(\n                trial_state, new_state, trial, trial_to_clone, new_config\n            )\n\n        new_tag = _make_experiment_tag(\n            trial_state.orig_tag, new_config, self._hyperparam_mutations\n        )\n        if trial.status == Trial.PAUSED:\n            # If trial is paused we update it with a new checkpoint.\n            # When the trial is started again, the new checkpoint is used.\n            if not self._synch:\n                raise TuneError(\n                    "Trials should be paused here only if in "\n                    "synchronous mode. If you encounter this error"\n                    " please raise an issue on Ray Github."\n                )\n        else:\n            trial_runner.pause_trial(trial, should_checkpoint=False)\n        trial.set_experiment_tag(new_tag)\n        # Clone hyperparameters from the `trial_to_clone`\n        trial.set_config(new_config)\n        # Resume training from a shallow copy of `trial_to_clone`\'s latest checkpoint\n        checkpoint_to_exploit = copy.copy(new_state.last_checkpoint)\n        # NOTE: Clear the checkpoint id (which was set by the other trial\'s\n        # checkpoint manager) so that the current trial\'s checkpoint manager marks\n        # the checkpoint as the most recent to use upon trial resume\n        checkpoint_to_exploit.id = None\n        trial.on_checkpoint(checkpoint_to_exploit)\n\n        self._num_perturbations += 1\n        # Transfer over the last perturbation time as well\n        trial_state.last_perturbation_time = new_state.last_perturbation_time\n        trial_state.last_train_time = new_state.last_train_time\n\n    def _quantiles(self) -> Tuple[List[Trial], List[Trial]]:\n        """Returns trials in the lower and upper `quantile` of the population.\n\n        If there is not enough data to compute this, returns empty lists.\n        """\n        trials = []\n        for trial, state in self._trial_state.items():\n            logger.debug("Trial {}, state {}".format(trial, state))\n            if trial.is_finished():\n                logger.debug("Trial {} is finished".format(trial))\n            if state.last_score is not None and not trial.is_finished():\n                trials.append(trial)\n        trials.sort(key=lambda t: self._trial_state[t].last_score)\n\n        if len(trials) <= 1:\n            return [], []\n        else:\n            num_trials_in_quantile = int(\n                math.ceil(len(trials) * self._quantile_fraction)\n            )\n            if num_trials_in_quantile > len(trials) / 2:\n                num_trials_in_quantile = int(math.floor(len(trials) / 2))\n            return (trials[:num_trials_in_quantile], trials[-num_trials_in_quantile:])\n\n    def choose_trial_to_run(\n        self, trial_runner: "trial_runner.TrialRunner"\n    ) -> Optional[Trial]:\n        """Ensures all trials get fair share of time (as defined by time_attr).\n\n        This enables the PBT scheduler to support a greater number of\n        concurrent trials than can fit in the cluster at any given time.\n        """\n        candidates = []\n        for trial in trial_runner.get_trials():\n            if (\n                trial.status\n                in [\n                    Trial.PENDING,\n                    Trial.PAUSED,\n                ]\n                and trial_runner.trial_executor.has_resources_for_trial(trial)\n            ):\n                if not self._synch:\n                    candidates.append(trial)\n                elif (\n                    self._trial_state[trial].last_train_time\n                    < self._next_perturbation_sync\n                ):\n                    candidates.append(trial)\n        candidates.sort(key=lambda trial: self._trial_state[trial].last_train_time)\n        return candidates[0] if candidates else None\n\n    # Unit test only. TODO(xwjiang): Remove test-specific APIs.\n    def reset_stats(self):\n        self._num_perturbations = 0\n        self._num_checkpoints = 0\n\n    # Unit test only. TODO(xwjiang): Remove test-specific APIs.\n    def last_scores(self, trials: List[Trial]) -> List[float]:\n        scores = []\n        for trial in trials:\n            state = self._trial_state[trial]\n            if state.last_score is not None and not trial.is_finished():\n                scores.append(state.last_score)\n        return scores\n\n    def debug_string(self) -> str:\n        return "PopulationBasedTraining: {} checkpoints, {} perturbs".format(\n            self._num_checkpoints, self._num_perturbations\n        )\n\n\n@PublicAPI\nclass PopulationBasedTrainingReplay(FIFOScheduler):\n    """Replays a Population Based Training run.\n\n    Population Based Training does not return a single hyperparameter\n    configuration, but rather a schedule of configurations. For instance,\n    PBT might discover that a larger learning rate leads to good results\n    in the first training iterations, but that a smaller learning rate\n    is preferable later.\n\n    This scheduler enables replaying these parameter schedules from\n    a finished PBT run. This requires that population based training has\n    been run with ``log_config=True``, which is the default setting.\n\n    The scheduler will only accept and train a single trial. It will\n    start with the initial config of the existing trial and update the\n    config according to the schedule.\n\n    Args:\n        policy_file: The PBT policy file. Usually this is\n            stored in ``~/ray_results/experiment_name/pbt_policy_xxx.txt``\n            where ``xxx`` is the trial ID.\n\n    Example:\n\n    .. code-block:: python\n\n        # Replaying a result from ray.tune.examples.pbt_convnet_example\n        from ray import air, tune\n\n        from ray.tune.examples.pbt_convnet_example import PytorchTrainable\n        from ray.tune.schedulers import PopulationBasedTrainingReplay\n\n        replay = PopulationBasedTrainingReplay(\n            "~/ray_results/pbt_test/pbt_policy_XXXXX_00001.txt")\n\n        tuner = tune.Tuner(\n            PytorchTrainable,\n            run_config=air.RunConfig(\n                stop={"training_iteration": 100}\n            ),\n            tune_config=tune.TuneConfig(\n                scheduler=replay,\n            ),\n        )\n        tuner.fit()\n\n\n    """\n\n    def __init__(self, policy_file: str):\n        policy_file = os.path.expanduser(policy_file)\n        if not os.path.exists(policy_file):\n            raise ValueError("Policy file not found: {}".format(policy_file))\n\n        self.policy_file = policy_file\n\n        # Find and read pbt policy file, potentially raise error\n        initial_config, self._policy = self._load_policy(self.policy_file)\n\n        self.experiment_tag = "replay_{}".format(os.path.basename(self.policy_file))\n        self.config = initial_config\n        self.current_config = self.config\n\n        self._trial = None\n        self._current_step = 0\n        self._num_perturbations = 0\n\n        self._policy_iter = iter(self._policy)\n        self._next_policy = next(self._policy_iter, None)\n\n    def _load_policy(self, policy_file: str) -> Tuple[Dict, List[Tuple[int, Dict]]]:\n        raw_policy = []\n        with open(policy_file, "rt") as fp:\n            for row in fp.readlines():\n                try:\n                    parsed_row = json.loads(row)\n                except json.JSONDecodeError:\n                    raise ValueError(\n                        "Could not read PBT policy file: {}.".format(policy_file)\n                    ) from None\n                raw_policy.append(tuple(parsed_row))\n\n        # Loop through policy from end to start to obtain changepoints\n        policy = []\n        last_new_tag = None\n        last_old_conf = None\n        for (old_tag, new_tag, old_step, new_step, old_conf, new_conf) in reversed(\n            raw_policy\n        ):\n            if last_new_tag and old_tag != last_new_tag:\n                # Tag chain ended. This means that previous changes were\n                # overwritten by the last change and should be ignored.\n                break\n            last_new_tag = new_tag\n            last_old_conf = old_conf\n\n            policy.append((new_step, new_conf))\n\n        return last_old_conf, list(reversed(policy))\n\n    def on_trial_add(self, trial_runner: "trial_runner.TrialRunner", trial: Trial):\n        if self._trial:\n            raise ValueError(\n                "More than one trial added to PBT replay run. This "\n                "means the same schedule will be trained multiple "\n                "times. Do you want to set `n_samples=1`?"\n            )\n        self._trial = trial\n        if self._trial.config and self._policy:\n            logger.warning(\n                "Trial was initialized with a config, which was overwritten. "\n                "Did you start the PBT replay with a `config` parameter?"\n            )\n        elif self._trial.config and not self._policy:\n            # Only train with initial policy\n            self.config = self._trial.config\n        elif not self._trial.config and not self._policy:\n            raise ValueError(\n                "No replay policy found and trial initialized without a "\n                "valid config. Either pass a `config` argument to `tune.Tuner()`"\n                "or consider not using PBT replay for this run."\n            )\n        self._trial.set_config(self.config)\n\n    def on_trial_result(\n        self, trial_runner: "trial_runner.TrialRunner", trial: Trial, result: Dict\n    ) -> str:\n        if TRAINING_ITERATION not in result:\n            # No time reported\n            return TrialScheduler.CONTINUE\n\n        if not self._next_policy:\n            # No more changes in the config\n            return TrialScheduler.CONTINUE\n\n        step = result[TRAINING_ITERATION]\n        self._current_step = step\n\n        change_at, new_config = self._next_policy\n\n        if step < change_at:\n            # Don\'t change the policy just yet\n            return TrialScheduler.CONTINUE\n\n        logger.info(\n            "Population Based Training replay is now at step {}. "\n            "Configuration will be changed to {}.".format(step, new_config)\n        )\n\n        checkpoint = trial_runner.trial_executor.save(\n            trial, CheckpointStorage.MEMORY, result=result\n        )\n\n        new_tag = _make_experiment_tag(self.experiment_tag, new_config, new_config)\n\n        trial_runner.pause_trial(trial, should_checkpoint=False)\n        trial.set_experiment_tag(new_tag)\n        trial.set_config(new_config)\n        trial.on_checkpoint(checkpoint)\n\n        self.current_config = new_config\n        self._num_perturbations += 1\n        self._next_policy = next(self._policy_iter, None)\n\n        return TrialScheduler.NOOP\n\n    def debug_string(self) -> str:\n        return "PopulationBasedTraining replay: Step {}, perturb {}".format(\n            self._current_step, self._num_perturbations\n        )\n',
            'python/ray/tune/tests/test_trial_scheduler.py': 'from collections import Counter\nimport os\nimport json\nimport random\nimport unittest\nimport time\n\nimport numpy as np\nimport sys\nimport tempfile\nimport shutil\nfrom unittest.mock import MagicMock\n\nimport ray\nfrom ray import tune\nfrom ray.air import CheckpointConfig\nfrom ray.air._internal.checkpoint_manager import _TrackedCheckpoint, CheckpointStorage\nfrom ray.tune import Trainable\nfrom ray.tune.execution.checkpoint_manager import _CheckpointManager\nfrom ray.tune.execution.ray_trial_executor import RayTrialExecutor\nfrom ray.tune.result import TRAINING_ITERATION\nfrom ray.tune.schedulers import (\n    FIFOScheduler,\n    HyperBandScheduler,\n    AsyncHyperBandScheduler,\n    PopulationBasedTraining,\n    MedianStoppingRule,\n    TrialScheduler,\n    HyperBandForBOHB,\n)\n\nfrom ray.tune.schedulers.pbt import _explore, PopulationBasedTrainingReplay\nfrom ray.tune.search._mock import _MockSearcher\nfrom ray.tune.search import ConcurrencyLimiter\nfrom ray.tune.experiment import Trial\nfrom ray.tune.resources import Resources\n\nfrom ray.rllib import _register_all\n\n_register_all()\n\n\ndef result(t, rew):\n    return dict(time_total_s=t, episode_reward_mean=rew, training_iteration=int(t))\n\n\ndef mock_trial_runner(trials=None):\n    trial_runner = MagicMock()\n    trial_runner.get_trials.return_value = trials or []\n    return trial_runner\n\n\nclass EarlyStoppingSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def basicSetup(self, rule):\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        runner = mock_trial_runner()\n        for i in range(10):\n            r1 = result(i, i * 100)\n            print("basicSetup:", i)\n            self.assertEqual(\n                rule.on_trial_result(runner, t1, r1), TrialScheduler.CONTINUE\n            )\n        for i in range(5):\n            r2 = result(i, 450)\n            self.assertEqual(\n                rule.on_trial_result(runner, t2, r2), TrialScheduler.CONTINUE\n            )\n        return t1, t2\n\n    def testMedianStoppingConstantPerf(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(5, 450)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(6, 0)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(10, 450)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingOnCompleteOnly(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(100, 0)), TrialScheduler.CONTINUE\n        )\n        rule.on_trial_complete(runner, t1, result(101, 1000))\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result(101, 0)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingGracePeriod(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=2.5,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        rule.on_trial_complete(runner, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(1, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(2, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(3, 10)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingMinSamples(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=2,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        t3 = Trial("PPO")\n        # Insufficient samples to evaluate t3\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(5, 10)), TrialScheduler.CONTINUE\n        )\n        rule.on_trial_complete(runner, t2, result(5, 1000))\n        # Sufficient samples to evaluate t3\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(5, 10)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingUsesMedian(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        rule.on_trial_complete(runner, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(1, 260)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(2, 260)), TrialScheduler.STOP\n        )\n\n    def testMedianStoppingSoftStop(self):\n        rule = MedianStoppingRule(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=0,\n            min_samples_required=1,\n            hard_stop=False,\n        )\n        t1, t2 = self.basicSetup(rule)\n        runner = mock_trial_runner()\n        rule.on_trial_complete(runner, t1, result(10, 1000))\n        rule.on_trial_complete(runner, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(1, 260)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t3, result(2, 260)), TrialScheduler.PAUSE\n        )\n\n    def _test_metrics(self, result_func, metric, mode):\n        rule = MedianStoppingRule(\n            grace_period=0,\n            min_samples_required=1,\n            time_attr="training_iteration",\n            metric=metric,\n            mode=mode,\n        )\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        runner = mock_trial_runner()\n        for i in range(10):\n            self.assertEqual(\n                rule.on_trial_result(runner, t1, result_func(i, i * 100)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(5):\n            self.assertEqual(\n                rule.on_trial_result(runner, t2, result_func(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        rule.on_trial_complete(runner, t1, result_func(10, 1000))\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result_func(5, 450)),\n            TrialScheduler.CONTINUE,\n        )\n        self.assertEqual(\n            rule.on_trial_result(runner, t2, result_func(6, 0)), TrialScheduler.CONTINUE\n        )\n\n    def testAlternateMetrics(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, neg_mean_loss=rew)\n\n        self._test_metrics(result2, "neg_mean_loss", "max")\n\n    def testAlternateMetricsMin(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, mean_loss=-rew)\n\n        self._test_metrics(result2, "mean_loss", "min")\n\n\n# Only barebone impl for start/stop_trial. No internal state maintained.\nclass _MockTrialExecutor(RayTrialExecutor):\n    def start_trial(self, trial, checkpoint_obj=None, train=True):\n        trial.logger_running = True\n        trial.restored_checkpoint = checkpoint_obj.dir_or_data\n        trial.status = Trial.RUNNING\n        return True\n\n    def stop_trial(self, trial, error=False, error_msg=None):\n        trial.status = Trial.ERROR if error else Trial.TERMINATED\n\n    def restore(self, trial, checkpoint=None, block=False):\n        pass\n\n    def save(self, trial, type=CheckpointStorage.PERSISTENT, result=None):\n        if type == CheckpointStorage.MEMORY:\n            checkpoint = _TrackedCheckpoint(\n                dir_or_data={"data": trial.trainable_name},\n                storage_mode=CheckpointStorage.MEMORY,\n                metrics=result,\n            )\n            trial.on_checkpoint(checkpoint)\n            return checkpoint\n        else:\n            return _TrackedCheckpoint(\n                dir_or_data=trial.trainable_name,\n                storage_mode=CheckpointStorage.PERSISTENT,\n                metrics=result,\n            )\n\n    def reset_trial(self, trial, new_config, new_experiment_tag):\n        return False\n\n    def debug_string(self):\n        return "This is a mock TrialExecutor."\n\n    def export_trial_if_needed(self):\n        return {}\n\n    def fetch_result(self):\n        return []\n\n    def get_next_available_trial(self):\n        return None\n\n    def get_running_trials(self):\n        return []\n\n    def has_resources_for_trial(self, trial: Trial):\n        return True\n\n\nclass _MockTrialRunner:\n    def __init__(self, scheduler):\n        self._scheduler_alg = scheduler\n        self.search_alg = None\n        self.trials = []\n        self.trial_executor = _MockTrialExecutor()\n\n    def process_action(self, trial, action):\n        if action == TrialScheduler.CONTINUE:\n            pass\n        elif action == TrialScheduler.PAUSE:\n            self.pause_trial(trial)\n        elif action == TrialScheduler.STOP:\n            self.trial_executor.stop_trial(trial)\n\n    def pause_trial(self, trial, should_checkpoint: bool = True):\n        if should_checkpoint:\n            self.trial_executor.save(trial, CheckpointStorage.MEMORY, None)\n        trial.status = Trial.PAUSED\n\n    def stop_trial(self, trial):\n        if trial.status in [Trial.ERROR, Trial.TERMINATED]:\n            return\n        elif trial.status in [Trial.PENDING, Trial.PAUSED]:\n            self._scheduler_alg.on_trial_remove(self, trial)\n        else:\n            self._scheduler_alg.on_trial_complete(self, trial, result(100, 10))\n\n    def add_trial(self, trial):\n        self.trials.append(trial)\n        self._scheduler_alg.on_trial_add(self, trial)\n\n    def get_trials(self):\n        return self.trials\n\n    def get_live_trials(self):\n        return {t for t in self.trials if t.status != Trial.TERMINATED}\n\n    def _launch_trial(self, trial):\n        trial.status = Trial.RUNNING\n\n\nclass HyperbandSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(object_store_memory=int(1e8))\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def schedulerSetup(self, num_trials, max_t=81):\n        """Setup a scheduler and Runner with max Iter = 9.\n\n        Bracketing is placed as follows:\n        (5, 81);\n        (8, 27) -> (3, 54);\n        (15, 9) -> (5, 27) -> (2, 45);\n        (34, 3) -> (12, 9) -> (4, 27) -> (2, 42);\n        (81, 1) -> (27, 3) -> (9, 9) -> (3, 27) -> (1, 41);"""\n        sched = HyperBandScheduler(\n            metric="episode_reward_mean", mode="max", max_t=max_t\n        )\n        for i in range(num_trials):\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n        runner = _MockTrialRunner(sched)\n        return sched, runner\n\n    def default_statistics(self):\n        """Default statistics for HyperBand."""\n        sched = HyperBandScheduler()\n        res = {\n            str(s): {"n": sched._get_n0(s), "r": sched._get_r0(s)}  # noqa\n            for s in range(sched._s_max_1)\n        }\n        res["max_trials"] = sum(v["n"] for v in res.values())\n        res["brack_count"] = sched._s_max_1\n        res["s_max"] = sched._s_max_1 - 1\n        return res\n\n    def downscale(self, n, sched):\n        return int(np.ceil(n / sched._eta))\n\n    def basicSetup(self):\n        """Setup and verify full band."""\n\n        stats = self.default_statistics()\n        sched, _ = self.schedulerSetup(stats["max_trials"])\n\n        self.assertEqual(len(sched._hyperbands), 1)\n        self.assertEqual(sched._cur_band_filled(), True)\n\n        filled_band = sched._hyperbands[0]\n        for bracket in filled_band:\n            self.assertEqual(bracket.filled(), True)\n        return sched\n\n    def advancedSetup(self):\n        sched = self.basicSetup()\n        for i in range(4):\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n\n        self.assertEqual(sched._cur_band_filled(), False)\n\n        unfilled_band = sched._hyperbands[-1]\n        self.assertEqual(len(unfilled_band), 2)\n        bracket = unfilled_band[-1]\n        self.assertEqual(bracket.filled(), False)\n        self.assertEqual(len(bracket.current_trials()), 7)\n\n        return sched\n\n    def testConfigSameEta(self):\n        sched = HyperBandScheduler(metric="episode_reward_mean", mode="max")\n        i = 0\n        while not sched._cur_band_filled():\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n            i += 1\n        self.assertEqual(len(sched._hyperbands[0]), 5)\n        self.assertEqual(sched._hyperbands[0][0]._n, 5)\n        self.assertEqual(sched._hyperbands[0][0]._r, 81)\n        self.assertEqual(sched._hyperbands[0][-1]._n, 81)\n        self.assertEqual(sched._hyperbands[0][-1]._r, 1)\n\n        reduction_factor = 10\n        sched = HyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            max_t=1000,\n            reduction_factor=reduction_factor,\n        )\n        i = 0\n        while not sched._cur_band_filled():\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n            i += 1\n        self.assertEqual(len(sched._hyperbands[0]), 4)\n        self.assertEqual(sched._hyperbands[0][0]._n, 4)\n        self.assertEqual(sched._hyperbands[0][0]._r, 1000)\n        self.assertEqual(sched._hyperbands[0][-1]._n, 1000)\n        self.assertEqual(sched._hyperbands[0][-1]._r, 1)\n\n    def testConfigSameEtaSmall(self):\n        sched = HyperBandScheduler(metric="episode_reward_mean", mode="max", max_t=1)\n        i = 0\n        while len(sched._hyperbands) < 2:\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n            i += 1\n        self.assertEqual(len(sched._hyperbands[0]), 1)\n\n    def testSuccessiveHalving(self):\n        """Setup full band, then iterate through last bracket (n=81)\n        to make sure successive halving is correct."""\n\n        stats = self.default_statistics()\n        sched, mock_runner = self.schedulerSetup(stats["max_trials"])\n        big_bracket = sched._state["bracket"]\n        cur_units = stats[str(stats["s_max"])]["r"]\n        # The last bracket will downscale 4 times\n        for x in range(stats["brack_count"] - 1):\n            trials = big_bracket.current_trials()\n            current_length = len(trials)\n            for trl in trials:\n                mock_runner._launch_trial(trl)\n\n            # Provides results from 0 to 8 in order, keeping last one running\n            for i, trl in enumerate(trials):\n                action = sched.on_trial_result(mock_runner, trl, result(cur_units, i))\n                if i < current_length - 1:\n                    self.assertEqual(action, TrialScheduler.PAUSE)\n                mock_runner.process_action(trl, action)\n\n            self.assertEqual(action, TrialScheduler.CONTINUE)\n            new_length = len(big_bracket.current_trials())\n            self.assertEqual(new_length, self.downscale(current_length, sched))\n            cur_units = int(cur_units * sched._eta)\n        self.assertEqual(len(big_bracket.current_trials()), 1)\n\n    def testHalvingStop(self):\n        stats = self.default_statistics()\n        num_trials = stats[str(0)]["n"] + stats[str(1)]["n"]\n        sched, mock_runner = self.schedulerSetup(num_trials)\n        big_bracket = sched._state["bracket"]\n        for trl in big_bracket.current_trials():\n            mock_runner._launch_trial(trl)\n\n        # # Provides result in reverse order, killing the last one\n        cur_units = stats[str(1)]["r"]\n        for i, trl in reversed(list(enumerate(big_bracket.current_trials()))):\n            action = sched.on_trial_result(mock_runner, trl, result(cur_units, i))\n            mock_runner.process_action(trl, action)\n\n        self.assertEqual(action, TrialScheduler.STOP)\n\n    def testStopsLastOne(self):\n        stats = self.default_statistics()\n        num_trials = stats[str(0)]["n"]  # setup one bracket\n        sched, mock_runner = self.schedulerSetup(num_trials)\n        big_bracket = sched._state["bracket"]\n        for trl in big_bracket.current_trials():\n            mock_runner._launch_trial(trl)\n\n        # # Provides result in reverse order, killing the last one\n        cur_units = stats[str(0)]["r"]\n        for i, trl in enumerate(big_bracket.current_trials()):\n            action = sched.on_trial_result(mock_runner, trl, result(cur_units, i))\n            mock_runner.process_action(trl, action)\n\n        self.assertEqual(action, TrialScheduler.STOP)\n\n    def testTrialErrored(self):\n        """If a trial errored, make sure successive halving still happens"""\n\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + 3\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        t1, t2, t3 = sched._state["bracket"].current_trials()\n        for t in [t1, t2, t3]:\n            mock_runner._launch_trial(t)\n\n        sched.on_trial_error(mock_runner, t3)\n        self.assertEqual(\n            TrialScheduler.PAUSE,\n            sched.on_trial_result(mock_runner, t1, result(stats[str(1)]["r"], 10)),\n        )\n        self.assertEqual(\n            TrialScheduler.CONTINUE,\n            sched.on_trial_result(mock_runner, t2, result(stats[str(1)]["r"], 10)),\n        )\n\n    def testTrialErrored2(self):\n        """Check successive halving happened even when last trial failed"""\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + stats[str(1)]["n"]\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        trials = sched._state["bracket"].current_trials()\n        for t in trials[:-1]:\n            mock_runner._launch_trial(t)\n            sched.on_trial_result(mock_runner, t, result(stats[str(1)]["r"], 10))\n\n        mock_runner._launch_trial(trials[-1])\n        sched.on_trial_error(mock_runner, trials[-1])\n        self.assertEqual(\n            len(sched._state["bracket"].current_trials()),\n            self.downscale(stats[str(1)]["n"], sched),\n        )\n\n    def testTrialEndedEarly(self):\n        """Check successive halving happened even when one trial failed"""\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + 3\n        sched, mock_runner = self.schedulerSetup(trial_count)\n\n        t1, t2, t3 = sched._state["bracket"].current_trials()\n        for t in [t1, t2, t3]:\n            mock_runner._launch_trial(t)\n\n        sched.on_trial_complete(mock_runner, t3, result(1, 12))\n        self.assertEqual(\n            TrialScheduler.PAUSE,\n            sched.on_trial_result(mock_runner, t1, result(stats[str(1)]["r"], 10)),\n        )\n        self.assertEqual(\n            TrialScheduler.CONTINUE,\n            sched.on_trial_result(mock_runner, t2, result(stats[str(1)]["r"], 10)),\n        )\n\n    def testTrialEndedEarly2(self):\n        """Check successive halving happened even when last trial failed"""\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + stats[str(1)]["n"]\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        trials = sched._state["bracket"].current_trials()\n        for t in trials[:-1]:\n            mock_runner._launch_trial(t)\n            sched.on_trial_result(mock_runner, t, result(stats[str(1)]["r"], 10))\n\n        mock_runner._launch_trial(trials[-1])\n        sched.on_trial_complete(mock_runner, trials[-1], result(100, 12))\n        self.assertEqual(\n            len(sched._state["bracket"].current_trials()),\n            self.downscale(stats[str(1)]["n"], sched),\n        )\n\n    def testAddAfterHalving(self):\n        stats = self.default_statistics()\n        trial_count = stats[str(0)]["n"] + 1\n        sched, mock_runner = self.schedulerSetup(trial_count)\n        bracket_trials = sched._state["bracket"].current_trials()\n        init_units = stats[str(1)]["r"]\n\n        for t in bracket_trials:\n            mock_runner._launch_trial(t)\n\n        for i, t in enumerate(bracket_trials):\n            action = sched.on_trial_result(mock_runner, t, result(init_units, i))\n        self.assertEqual(action, TrialScheduler.CONTINUE)\n        t = Trial("__fake")\n        sched.on_trial_add(None, t)\n        mock_runner._launch_trial(t)\n        self.assertEqual(len(sched._state["bracket"].current_trials()), 2)\n\n        # Make sure that newly added trial gets fair computation (not just 1)\n        self.assertEqual(\n            TrialScheduler.CONTINUE,\n            sched.on_trial_result(mock_runner, t, result(init_units, 12)),\n        )\n        new_units = init_units + int(init_units * sched._eta)\n        self.assertEqual(\n            TrialScheduler.PAUSE,\n            sched.on_trial_result(mock_runner, t, result(new_units, 12)),\n        )\n\n    def _test_metrics(self, result_func, metric, mode):\n        sched = HyperBandScheduler(time_attr="time_total_s", metric=metric, mode=mode)\n        stats = self.default_statistics()\n\n        for i in range(stats["max_trials"]):\n            t = Trial("__fake")\n            sched.on_trial_add(None, t)\n        runner = _MockTrialRunner(sched)\n\n        big_bracket = sched._hyperbands[0][-1]\n\n        for trl in big_bracket.current_trials():\n            runner._launch_trial(trl)\n        current_length = len(big_bracket.current_trials())\n\n        # Provides results from 0 to 8 in order, keeping the last one running\n        for i, trl in enumerate(big_bracket.current_trials()):\n            action = sched.on_trial_result(runner, trl, result_func(1, i))\n            runner.process_action(trl, action)\n\n        new_length = len(big_bracket.current_trials())\n        self.assertEqual(action, TrialScheduler.CONTINUE)\n        self.assertEqual(new_length, self.downscale(current_length, sched))\n\n    def testAlternateMetrics(self):\n        """Checking that alternate metrics will pass."""\n\n        def result2(t, rew):\n            return dict(time_total_s=t, neg_mean_loss=rew)\n\n        self._test_metrics(result2, "neg_mean_loss", "max")\n\n    def testAlternateMetricsMin(self):\n        """Checking that alternate metrics will pass."""\n\n        def result2(t, rew):\n            return dict(time_total_s=t, mean_loss=-rew)\n\n        self._test_metrics(result2, "mean_loss", "min")\n\n    def testJumpingTime(self):\n        sched, mock_runner = self.schedulerSetup(81)\n        big_bracket = sched._hyperbands[0][-1]\n\n        for trl in big_bracket.current_trials():\n            mock_runner._launch_trial(trl)\n\n        # Provides results from 0 to 8 in order, keeping the last one running\n        main_trials = big_bracket.current_trials()[:-1]\n        jump = big_bracket.current_trials()[-1]\n        for i, trl in enumerate(main_trials):\n            action = sched.on_trial_result(mock_runner, trl, result(1, i))\n            mock_runner.process_action(trl, action)\n\n        action = sched.on_trial_result(mock_runner, jump, result(4, i))\n        self.assertEqual(action, TrialScheduler.PAUSE)\n\n        current_length = len(big_bracket.current_trials())\n        self.assertLess(current_length, 27)\n\n    def testRemove(self):\n        """Test with 4: start 1, remove 1 pending, add 2, remove 1 pending."""\n        sched, runner = self.schedulerSetup(4)\n        trials = sorted(sched._trial_info, key=lambda t: t.trial_id)\n        runner._launch_trial(trials[0])\n        sched.on_trial_result(runner, trials[0], result(1, 5))\n        self.assertEqual(trials[0].status, Trial.RUNNING)\n        self.assertEqual(trials[1].status, Trial.PENDING)\n\n        bracket, _ = sched._trial_info[trials[1]]\n        self.assertTrue(trials[1] in bracket._live_trials)\n        sched.on_trial_remove(runner, trials[1])\n        self.assertFalse(trials[1] in bracket._live_trials)\n\n        for i in range(2):\n            trial = Trial("__fake")\n            sched.on_trial_add(None, trial)\n\n        bracket, _ = sched._trial_info[trial]\n        self.assertTrue(trial in bracket._live_trials)\n        sched.on_trial_remove(runner, trial)  # where trial is not running\n        self.assertFalse(trial in bracket._live_trials)\n\n    def testFilterNoneBracket(self):\n        sched, runner = self.schedulerSetup(100, 20)\n        # "sched" should contains None brackets\n        non_brackets = [\n            b for hyperband in sched._hyperbands for b in hyperband if b is None\n        ]\n        self.assertTrue(non_brackets)\n        # Make sure "choose_trial_to_run" still works\n        trial = sched.choose_trial_to_run(runner)\n        self.assertIsNotNone(trial)\n\n\nclass BOHBSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(object_store_memory=int(1e8))\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def testLargestBracketFirst(self):\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="max", max_t=3, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        for i in range(3):\n            t = Trial("__fake")\n            sched.on_trial_add(runner, t)\n            runner._launch_trial(t)\n\n        self.assertEqual(sched.state()["num_brackets"], 1)\n        sched.on_trial_add(runner, Trial("__fake"))\n        self.assertEqual(sched.state()["num_brackets"], 2)\n\n    def testCheckTrialInfoUpdate(self):\n        def result(score, ts):\n            return {"episode_reward_mean": score, TRAINING_ITERATION: ts}\n\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="max", max_t=3, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n        trials = [Trial("__fake") for i in range(3)]\n        for t in trials:\n            runner.add_trial(t)\n            runner._launch_trial(t)\n\n        for trial, trial_result in zip(trials, [result(1, 1), result(2, 1)]):\n            decision = sched.on_trial_result(runner, trial, trial_result)\n            self.assertEqual(decision, TrialScheduler.PAUSE)\n            runner.pause_trial(trial)\n        spy_result = result(0, 1)\n        decision = sched.on_trial_result(runner, trials[-1], spy_result)\n        self.assertEqual(decision, TrialScheduler.STOP)\n        sched.choose_trial_to_run(runner)\n        self.assertEqual(runner._search_alg.searcher.on_pause.call_count, 2)\n        self.assertEqual(runner._search_alg.searcher.on_unpause.call_count, 1)\n        self.assertTrue("hyperband_info" in spy_result)\n        self.assertEqual(spy_result["hyperband_info"]["budget"], 1)\n\n    def testCheckTrialInfoUpdateMin(self):\n        def result(score, ts):\n            return {"episode_reward_mean": score, TRAINING_ITERATION: ts}\n\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="min", max_t=3, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n        trials = [Trial("__fake") for i in range(3)]\n        for t in trials:\n            runner.add_trial(t)\n            runner._launch_trial(t)\n\n        for trial, trial_result in zip(trials, [result(1, 1), result(2, 1)]):\n            decision = sched.on_trial_result(runner, trial, trial_result)\n            self.assertEqual(decision, TrialScheduler.PAUSE)\n            runner.pause_trial(trial)\n        spy_result = result(0, 1)\n        decision = sched.on_trial_result(runner, trials[-1], spy_result)\n        self.assertEqual(decision, TrialScheduler.CONTINUE)\n        sched.choose_trial_to_run(runner)\n        self.assertEqual(runner._search_alg.searcher.on_pause.call_count, 2)\n        self.assertTrue("hyperband_info" in spy_result)\n        self.assertEqual(spy_result["hyperband_info"]["budget"], 1)\n\n    def testPauseResumeChooseTrial(self):\n        def result(score, ts):\n            return {"episode_reward_mean": score, TRAINING_ITERATION: ts}\n\n        sched = HyperBandForBOHB(\n            metric="episode_reward_mean", mode="min", max_t=10, reduction_factor=3\n        )\n        runner = _MockTrialRunner(sched)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n        trials = [Trial("__fake") for i in range(3)]\n        for t in trials:\n            runner.add_trial(t)\n            runner._launch_trial(t)\n\n        all_results = [result(1, 5), result(2, 1), result(3, 5)]\n        for trial, trial_result in zip(trials, all_results):\n            decision = sched.on_trial_result(runner, trial, trial_result)\n            self.assertEqual(decision, TrialScheduler.PAUSE)\n            runner.pause_trial(trial)\n\n        run_trial = sched.choose_trial_to_run(runner)\n        self.assertEqual(run_trial, trials[1])\n        self.assertSequenceEqual(\n            [t.status for t in trials], [Trial.PAUSED, Trial.PENDING, Trial.PAUSED]\n        )\n\n    def testNonstopBOHB(self):\n        from ray.tune.search.bohb import TuneBOHB\n\n        def train(cfg, checkpoint_dir=None):\n            start = 0\n            if checkpoint_dir:\n                with open(os.path.join(checkpoint_dir, "checkpoint")) as f:\n                    start = int(f.read())\n\n            for i in range(start, 200):\n\n                time.sleep(0.1)\n                tune.report(episode_reward_mean=i)\n                with tune.checkpoint_dir(i) as checkpoint_dir:\n                    with open(os.path.join(checkpoint_dir, "checkpoint"), "w") as f:\n                        f.write(str(i))\n\n        config = {"test_variable": tune.uniform(0, 20)}\n        sched = HyperBandForBOHB(max_t=10, reduction_factor=3, stop_last_trials=False)\n        alg = ConcurrencyLimiter(TuneBOHB(), 4)\n        analysis = tune.run(\n            train,\n            scheduler=sched,\n            search_alg=alg,\n            stop={"training_iteration": 32},\n            num_samples=20,\n            config=config,\n            metric="episode_reward_mean",\n            mode="min",\n            verbose=1,\n            fail_fast="raise",\n        )\n        counter = Counter(\n            t.last_result.get("training_iteration") for t in analysis.trials\n        )\n        assert 32 in counter\n        assert counter[32] > 1\n\n\nclass _MockTrial(Trial):\n    def __init__(self, i, config):\n        self.trainable_name = "trial_{}".format(i)\n        self.trial_id = str(i)\n        self.config = config\n        self.experiment_tag = "{}tag".format(i)\n        self.trial_name_creator = None\n        self.logger_running = False\n        self.restored_checkpoint = None\n        self.resources = Resources(1, 0)\n        self.custom_trial_name = None\n        self.custom_dirname = None\n        self._default_result_or_future = None\n        self.checkpoint_manager = _CheckpointManager(\n            checkpoint_config=CheckpointConfig(\n                num_to_keep=2,\n                checkpoint_score_attribute="episode_reward_mean",\n            ),\n            delete_fn=lambda c: None,\n        )\n\n    def on_checkpoint(self, checkpoint):\n        super().on_checkpoint(checkpoint)\n        if checkpoint.storage_mode == CheckpointStorage.MEMORY:\n            self.restored_checkpoint = checkpoint.dir_or_data["data"]\n        else:\n            self.restored_checkpoint = checkpoint.dir_or_data\n\n\nclass PopulationBasedTestingSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    # Helper function to call pbt.on_trial_result and assert decision,\n    # or trial status upon existing.\n    # Need to have the `trial` in `RUNNING` status first.\n    def on_trial_result(self, pbt, runner, trial, result, expected_decision=None):\n        trial.status = Trial.RUNNING\n        decision = pbt.on_trial_result(runner, trial, result)\n        if expected_decision is None:\n            pass\n        elif expected_decision == TrialScheduler.PAUSE:\n            self.assertTrue(\n                trial.status == Trial.PAUSED or decision == expected_decision\n            )\n        elif expected_decision == TrialScheduler.CONTINUE:\n            self.assertEqual(decision, expected_decision)\n        return decision\n\n    def basicSetup(\n        self,\n        num_trials=5,\n        resample_prob=0.0,\n        explore=None,\n        perturbation_interval=10,\n        log_config=False,\n        require_attrs=True,\n        hyperparams=None,\n        hyperparam_mutations=None,\n        step_once=True,\n        synch=False,\n    ):\n        hyperparam_mutations = hyperparam_mutations or {\n            "float_factor": lambda: 100.0,\n            "int_factor": lambda: 10,\n            "id_factor": [100],\n        }\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="episode_reward_mean",\n            mode="max",\n            perturbation_interval=perturbation_interval,\n            resample_probability=resample_prob,\n            quantile_fraction=0.25,\n            hyperparam_mutations=hyperparam_mutations,\n            custom_explore_fn=explore,\n            log_config=log_config,\n            synch=synch,\n            require_attrs=require_attrs,\n        )\n        runner = _MockTrialRunner(pbt)\n        for i in range(num_trials):\n            trial_hyperparams = hyperparams or {\n                "float_factor": 2.0,\n                "const_factor": 3,\n                "int_factor": 10,\n                "id_factor": i,\n            }\n            trial = _MockTrial(i, trial_hyperparams)\n            runner.add_trial(trial)\n            trial.status = Trial.RUNNING\n        for i in range(num_trials):\n            trial = runner.trials[i]\n            if step_once:\n                if synch:\n                    self.on_trial_result(\n                        pbt,\n                        runner,\n                        trial,\n                        result(10, 50 * i),\n                        expected_decision=TrialScheduler.PAUSE,\n                    )\n                else:\n                    self.on_trial_result(\n                        pbt,\n                        runner,\n                        trial,\n                        result(10, 50 * i),\n                        expected_decision=TrialScheduler.CONTINUE,\n                    )\n        pbt.reset_stats()\n        return pbt, runner\n\n    def testSearchError(self):\n        pbt, runner = self.basicSetup(num_trials=0)\n\n        def mock_train(config):\n            return 1\n\n        with self.assertRaises(ValueError):\n            tune.run(\n                mock_train, config={"x": 1}, scheduler=pbt, search_alg=_MockSearcher()\n            )\n\n    def testMetricError(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n\n        # Should error if training_iteration not in result dict.\n        with self.assertRaises(RuntimeError):\n            self.on_trial_result(\n                pbt, runner, trials[0], result={"episode_reward_mean": 4}\n            )\n\n        # Should error if episode_reward_mean not in result dict.\n        with self.assertRaises(RuntimeError):\n            self.on_trial_result(\n                pbt,\n                runner,\n                trials[0],\n                result={"random_metric": 10, "training_iteration": 20},\n            )\n\n    def testMetricLog(self):\n        pbt, runner = self.basicSetup(require_attrs=False)\n        trials = runner.get_trials()\n\n        # Should not error if training_iteration not in result dict\n        with self.assertLogs("ray.tune.schedulers.pbt", level="WARN"):\n            self.on_trial_result(\n                pbt, runner, trials[0], result={"episode_reward_mean": 4}\n            )\n\n        # Should not error if episode_reward_mean not in result dict.\n        with self.assertLogs("ray.tune.schedulers.pbt", level="WARN"):\n            self.on_trial_result(\n                pbt,\n                runner,\n                trials[0],\n                result={"random_metric": 10, "training_iteration": 20},\n            )\n\n    def testCheckpointsMostPromisingTrials(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n\n        # no checkpoint: haven\'t hit next perturbation interval yet\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.on_trial_result(\n            pbt, runner, trials[0], result(15, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 0)\n\n        # checkpoint: both past interval and upper quantile\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [200, 50, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 1)\n        self.on_trial_result(\n            pbt, runner, trials[1], result(30, 201), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [200, 201, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 2)\n\n        # not upper quantile any more\n        self.on_trial_result(\n            pbt, runner, trials[4], result(30, 199), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt._num_checkpoints, 2)\n        self.assertEqual(pbt._num_perturbations, 0)\n\n    def testCheckpointMostPromisingTrialsSynch(self):\n        pbt, runner = self.basicSetup(synch=True)\n        trials = runner.get_trials()\n\n        # no checkpoint: haven\'t hit next perturbation interval yet\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.on_trial_result(\n            pbt, runner, trials[0], result(15, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertEqual(pbt._num_checkpoints, 0)\n\n        # trials should be paused until all trials are synced.\n        for i in range(len(trials) - 1):\n            self.on_trial_result(\n                pbt, runner, trials[i], result(20, 200 + i), TrialScheduler.PAUSE\n            )\n\n        self.assertEqual(pbt.last_scores(trials), [200, 201, 202, 203, 200])\n        self.assertEqual(pbt._num_checkpoints, 0)\n\n        self.on_trial_result(\n            pbt, runner, trials[-1], result(20, 204), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt._num_checkpoints, 2)\n\n    def testPerturbsLowPerformingTrials(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n\n        # no perturbation: haven\'t hit next perturbation interval\n        self.on_trial_result(\n            pbt, runner, trials[0], result(15, -100), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertTrue("@perturbed" not in trials[0].experiment_tag)\n        self.assertEqual(pbt._num_perturbations, 0)\n\n        # perturb since it\'s lower quantile\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [-100, 50, 100, 150, 200])\n        self.assertTrue("@perturbed" in trials[0].experiment_tag)\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(pbt._num_perturbations, 1)\n\n        # also perturbed\n        self.on_trial_result(\n            pbt, runner, trials[2], result(20, 40), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [-100, 50, 40, 150, 200])\n        self.assertEqual(pbt._num_perturbations, 2)\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertTrue("@perturbed" in trials[2].experiment_tag)\n\n    def testPerturbsLowPerformingTrialsSynch(self):\n        pbt, runner = self.basicSetup(synch=True)\n        trials = runner.get_trials()\n\n        # no perturbation: haven\'t hit next perturbation interval\n        self.on_trial_result(\n            pbt, runner, trials[-1], result(15, -100), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, 200])\n        self.assertTrue("@perturbed" not in trials[-1].experiment_tag)\n        self.assertEqual(pbt._num_perturbations, 0)\n\n        # Don\'t perturb until all trials are synched.\n        self.on_trial_result(\n            pbt, runner, trials[-1], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 50, 100, 150, -100])\n        self.assertTrue("@perturbed" not in trials[-1].experiment_tag)\n\n        # Synch all trials.\n        for i in range(len(trials) - 1):\n            self.on_trial_result(\n                pbt, runner, trials[i], result(20, -10 * i), TrialScheduler.PAUSE\n            )\n        self.assertEqual(pbt.last_scores(trials), [0, -10, -20, -30, -100])\n        self.assertIn(trials[-1].restored_checkpoint, ["trial_0", "trial_1"])\n        self.assertIn(trials[-2].restored_checkpoint, ["trial_0", "trial_1"])\n        self.assertEqual(pbt._num_perturbations, 2)\n\n    def testPerturbWithoutResample(self):\n        pbt, runner = self.basicSetup(resample_prob=0.0)\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertIn(trials[0].config["id_factor"], [100])\n        self.assertIn(trials[0].config["float_factor"], [2.4, 1.6])\n        self.assertEqual(type(trials[0].config["float_factor"]), float)\n        self.assertIn(trials[0].config["int_factor"], [8, 12])\n        self.assertEqual(type(trials[0].config["int_factor"]), int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n\n    def testPerturbWithResample(self):\n        pbt, runner = self.basicSetup(resample_prob=1.0)\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(trials[0].status, Trial.PAUSED)\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(trials[0].config["id_factor"], 100)\n        self.assertEqual(trials[0].config["float_factor"], 100.0)\n        self.assertEqual(type(trials[0].config["float_factor"]), float)\n        self.assertEqual(trials[0].config["int_factor"], 10)\n        self.assertEqual(type(trials[0].config["int_factor"]), int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n\n    def testExploitsCorrectCheckpoint(self):\n        """When trial 0 attempts to exploit trial 1, PBT replaces trial 0\'s in-memory\n        checkpoint with a copy of trial 1\'s in-memory checkpoint. A trial may have\n        both memory and persistent checkpoints, so this test checks that trial 0 uses\n        trial 1\'s in-memory checkpoint rather than its own persistent checkpoint, even\n        if trial 0\'s persistent checkpoint is more recent in terms of checkpoint id.\n        """\n        pbt, runner = self.basicSetup(\n            num_trials=2, perturbation_interval=1, step_once=False, synch=True\n        )\n        trials = runner.get_trials()\n\n        memory = _TrackedCheckpoint(\n            dir_or_data={"data": 0},\n            storage_mode=CheckpointStorage.MEMORY,\n            metrics=result(0, 0),\n        )\n        trials[0].on_checkpoint(memory)\n        self.assertEqual(trials[0].checkpoint, memory)\n        self.assertEqual(trials[0].checkpoint.id, 0)\n\n        # Save persistent checkpoint for trial 0 with a fresher checkpoint id\n        # This happens naturally in a regular run of PBT, since the CheckpointManager\n        # counters are not always in synch, and a trial\'s own persistent checkpoint\n        # could have a more recent checkpoint id if the memory checkpoint has been\n        # replaced with another trial\'s checkpoint\n        persistent = _TrackedCheckpoint(\n            dir_or_data="not used",\n            storage_mode=CheckpointStorage.PERSISTENT,\n            metrics=result(0, 0),\n        )\n        trials[0].on_checkpoint(persistent)\n        self.assertEqual(trials[0].checkpoint, persistent)\n        self.assertEqual(trials[0].checkpoint.id, 1)\n\n        # Trial 0 result, score=0\n        self.on_trial_result(pbt, runner, trials[0], result(1, 0), TrialScheduler.PAUSE)\n        # Trial 1 result, score=100\n        self.on_trial_result(\n            pbt, runner, trials[1], result(1, 100), TrialScheduler.PAUSE\n        )\n        trial1_checkpoint = trials[1].checkpoint\n        assert (\n            trial1_checkpoint\n        ), "Trial 1 should have saved a checkpoint, since it is in the upper quantile"\n        assert trials[0].checkpoint.storage_mode == CheckpointStorage.MEMORY, (\n            "Trial 0 should exploit trial 1 by using its in-memory checkpoint. Instead,"\n            " it\'s using a different checkpoint of type "\n            f"{trials[0].checkpoint.storage_mode}\\n"\n            f"Expected:\\n{trial1_checkpoint}\\nActual:\\n{trials[0].checkpoint}"\n        )\n        assert trials[0].checkpoint != memory\n        # PBT ensures that the exploited checkpoint is used by setting the id to 1\n        # more than the last checkpoint id (the persistent checkpoint had id = 1).\n        self.assertEqual(trials[0].checkpoint.id, 2)\n        assert trials[0].checkpoint.metrics.get("episode_reward_mean") == 100, (\n            "Trial 0\'s checkpoint (score=0) is not correctly exploiting "\n            "Trial 1\'s checkpoint (score=100)\\n"\n            f"Expected:\\n{trial1_checkpoint}\\nActual:\\n{trials[0].checkpoint}"\n        )\n\n    def testTuneSamplePrimitives(self):\n        pbt, runner = self.basicSetup(\n            resample_prob=1.0,\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "int_factor": lambda: 10,\n                "id_factor": tune.choice([100]),\n            },\n        )\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(trials[0].config["id_factor"], 100)\n        self.assertEqual(trials[0].config["float_factor"], 100.0)\n        self.assertEqual(type(trials[0].config["float_factor"]), float)\n        self.assertEqual(trials[0].config["int_factor"], 10)\n        self.assertEqual(type(trials[0].config["int_factor"]), int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n\n    def testTuneSampleFromError(self):\n        with self.assertRaises(ValueError):\n            pbt, runner = self.basicSetup(\n                hyperparam_mutations={"float_factor": tune.sample_from(lambda: 100.0)}\n            )\n\n    def testPerturbationValues(self):\n        def assertProduces(fn, values):\n            random.seed(0)\n            seen = set()\n            for _ in range(100):\n                seen.add(fn()["v"])\n            self.assertEqual(seen, values)\n\n        def explore_fn(\n            config, mutations, resample_probability, custom_explore_fn=lambda x: x\n        ):\n            new_config, _ = _explore(\n                config,\n                mutations,\n                resample_probability,\n                perturbation_factors=(1.2, 0.8),\n                custom_explore_fn=custom_explore_fn,\n            )\n            return new_config\n\n        # Categorical case\n        assertProduces(lambda: explore_fn({"v": 4}, {"v": [3, 4, 8, 10]}, 0.0), {3, 8})\n        assertProduces(lambda: explore_fn({"v": 3}, {"v": [3, 4, 8, 10]}, 0.0), {3, 4})\n        assertProduces(\n            lambda: explore_fn({"v": 10}, {"v": [3, 4, 8, 10]}, 0.0), {8, 10}\n        )\n        assertProduces(\n            lambda: explore_fn({"v": 7}, {"v": [3, 4, 8, 10]}, 0.0),\n            {3, 4, 8, 10},\n        )\n        assertProduces(\n            lambda: explore_fn({"v": 4}, {"v": [3, 4, 8, 10]}, 1.0),\n            {3, 4, 8, 10},\n        )\n\n        # Check that tuple also works\n        assertProduces(lambda: explore_fn({"v": 4}, {"v": (3, 4, 8, 10)}, 0.0), {3, 8})\n        assertProduces(lambda: explore_fn({"v": 3}, {"v": (3, 4, 8, 10)}, 0.0), {3, 4})\n\n        # Passing in an invalid types should raise an error\n        with self.assertRaises(ValueError):\n            explore_fn({"v": 4}, {"v": {3, 4, 8, 10}}, 0.0)\n        with self.assertRaises(ValueError):\n            explore_fn({"v": 4}, {"v": "invalid"}, 0.0)\n\n        # Continuous case\n        assertProduces(\n            lambda: explore_fn(\n                {"v": 100}, {"v": lambda: random.choice([10, 100])}, 0.0\n            ),\n            {80, 120},\n        )\n        assertProduces(\n            lambda: explore_fn(\n                {"v": 100.0}, {"v": lambda: random.choice([10, 100])}, 0.0\n            ),\n            {80.0, 120.0},\n        )\n        assertProduces(\n            lambda: explore_fn(\n                {"v": 100.0}, {"v": lambda: random.choice([10, 100])}, 1.0\n            ),\n            {10.0, 100.0},\n        )\n\n        def deep_add(seen, new_values):\n            for k, new_value in new_values.items():\n                if isinstance(new_value, dict):\n                    if k not in seen:\n                        seen[k] = {}\n                    seen[k].update(deep_add(seen[k], new_value))\n                else:\n                    if k not in seen:\n                        seen[k] = set()\n                    seen[k].add(new_value)\n\n            return seen\n\n        def assertNestedProduces(fn, values):\n            random.seed(0)\n            seen = {}\n            for _ in range(100):\n                new_config = fn()\n                seen = deep_add(seen, new_config)\n            self.assertEqual(seen, values)\n\n        # Nested mutation and spec\n        assertNestedProduces(\n            lambda: explore_fn(\n                {\n                    "a": {"b": 4},\n                    "1": {"2": {"3": 100}},\n                },\n                {\n                    "a": {"b": [3, 4, 8, 10]},\n                    "1": {"2": {"3": lambda: random.choice([10, 100])}},\n                },\n                0.0,\n            ),\n            {\n                "a": {"b": {3, 8}},\n                "1": {"2": {"3": {80, 120}}},\n            },\n        )\n\n        custom_explore_fn = MagicMock(side_effect=lambda x: x)\n\n        # Nested mutation and spec\n        assertNestedProduces(\n            lambda: explore_fn(\n                {\n                    "a": {"b": 4},\n                    "1": {"2": {"3": 100}},\n                },\n                {\n                    "a": {"b": [3, 4, 8, 10]},\n                    "1": {"2": {"3": lambda: random.choice([10, 100])}},\n                },\n                0.0,\n                custom_explore_fn=custom_explore_fn,\n            ),\n            {\n                "a": {"b": {3, 8}},\n                "1": {"2": {"3": {80, 120}}},\n            },\n        )\n\n        # Expect call count to be 100 because we call explore 100 times\n        self.assertEqual(custom_explore_fn.call_count, 100)\n\n    def testDictPerturbation(self):\n        pbt, runner = self.basicSetup(\n            resample_prob=1.0,\n            hyperparams={\n                "float_factor": 2.0,\n                "nest": {"nest_float": 3.0},\n                "int_factor": 10,\n                "const_factor": 3,\n            },\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "nest": {"nest_float": lambda: 101.0},\n                "int_factor": lambda: 10,\n            },\n        )\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertIn(trials[0].restored_checkpoint, ["trial_3", "trial_4"])\n        self.assertEqual(trials[0].config["float_factor"], 100.0)\n        self.assertIsInstance(trials[0].config["float_factor"], float)\n        self.assertEqual(trials[0].config["int_factor"], 10)\n        self.assertIsInstance(trials[0].config["int_factor"], int)\n        self.assertEqual(trials[0].config["const_factor"], 3)\n        self.assertEqual(trials[0].config["nest"]["nest_float"], 101.0)\n        self.assertIsInstance(trials[0].config["nest"]["nest_float"], float)\n\n    def testYieldsTimeToOtherTrials(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n        trials[0].status = Trial.PENDING  # simulate not enough resources\n        self.on_trial_result(\n            pbt, runner, trials[1], result(20, 1000), TrialScheduler.PAUSE\n        )\n        self.assertEqual(pbt.last_scores(trials), [0, 1000, 100, 150, 200])\n        self.assertEqual(pbt.choose_trial_to_run(runner), trials[0])\n\n    def testSchedulesMostBehindTrialToRun(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n        self.on_trial_result(pbt, runner, trials[0], result(800, 1000))\n        self.on_trial_result(pbt, runner, trials[1], result(700, 1001))\n        self.on_trial_result(pbt, runner, trials[2], result(600, 1002))\n        self.on_trial_result(pbt, runner, trials[3], result(500, 1003))\n        self.on_trial_result(pbt, runner, trials[4], result(700, 1004))\n        self.assertEqual(pbt.choose_trial_to_run(runner), None)\n        for i in range(5):\n            trials[i].status = Trial.PENDING\n        self.assertEqual(pbt.choose_trial_to_run(runner), trials[3])\n\n    def testSchedulesMostBehindTrialToRunSynch(self):\n        pbt, runner = self.basicSetup(synch=True)\n        trials = runner.get_trials()\n        runner.process_action(\n            trials[0], self.on_trial_result(pbt, runner, trials[0], result(800, 1000))\n        )\n        runner.process_action(\n            trials[1], self.on_trial_result(pbt, runner, trials[1], result(700, 1001))\n        )\n        runner.process_action(\n            trials[2], self.on_trial_result(pbt, runner, trials[2], result(600, 1002))\n        )\n        runner.process_action(\n            trials[3], self.on_trial_result(pbt, runner, trials[3], result(500, 1003))\n        )\n        runner.process_action(\n            trials[4], self.on_trial_result(pbt, runner, trials[4], result(700, 1004))\n        )\n        self.assertIn(\n            pbt.choose_trial_to_run(runner), [trials[0], trials[1], trials[3]]\n        )\n\n    def testPerturbationResetsLastPerturbTime(self):\n        pbt, runner = self.basicSetup()\n        trials = runner.get_trials()\n        self.on_trial_result(pbt, runner, trials[0], result(10000, 1005))\n        self.on_trial_result(pbt, runner, trials[1], result(10000, 1004))\n        self.on_trial_result(pbt, runner, trials[2], result(600, 1003))\n        self.assertEqual(pbt._num_perturbations, 0)\n        self.on_trial_result(pbt, runner, trials[3], result(500, 1002))\n        self.assertEqual(pbt._num_perturbations, 1)\n        self.on_trial_result(pbt, runner, trials[3], result(600, 100))\n        self.assertEqual(pbt._num_perturbations, 1)\n        self.on_trial_result(pbt, runner, trials[3], result(11000, 100))\n        self.assertEqual(pbt._num_perturbations, 2)\n\n    def testLogConfig(self):\n        def check_policy(policy):\n            self.assertIsInstance(policy[2], int)\n            self.assertIsInstance(policy[3], int)\n            self.assertIn(policy[0], ["0tag", "2tag", "3tag", "4tag"])\n            self.assertIn(policy[1], ["0tag", "2tag", "3tag", "4tag"])\n            self.assertIn(policy[2], [0, 2, 3, 4])\n            self.assertIn(policy[3], [0, 2, 3, 4])\n            for i in [4, 5]:\n                self.assertIsInstance(policy[i], dict)\n                for key in ["const_factor", "int_factor", "float_factor", "id_factor"]:\n                    self.assertIn(key, policy[i])\n                self.assertIsInstance(policy[i]["float_factor"], float)\n                self.assertIsInstance(policy[i]["int_factor"], int)\n                self.assertIn(policy[i]["const_factor"], [3])\n                self.assertIn(policy[i]["int_factor"], [8, 10, 12])\n                self.assertIn(policy[i]["float_factor"], [2.4, 2, 1.6])\n                self.assertIn(policy[i]["id_factor"], [3, 4, 100])\n\n        pbt, runner = self.basicSetup(log_config=True)\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: i}\n        self.on_trial_result(pbt, runner, trials[0], result(15, -100))\n        self.on_trial_result(pbt, runner, trials[0], result(20, -100))\n        self.on_trial_result(pbt, runner, trials[2], result(20, 40))\n        log_files = ["pbt_global.txt", "pbt_policy_0.txt", "pbt_policy_2.txt"]\n        for log_file in log_files:\n            self.assertTrue(os.path.exists(os.path.join(tmpdir, log_file)))\n            raw_policy = open(os.path.join(tmpdir, log_file), "r").readlines()\n            for line in raw_policy:\n                check_policy(json.loads(line))\n        shutil.rmtree(tmpdir)\n\n    def testLogConfigSynch(self):\n        def check_policy(policy):\n            self.assertIsInstance(policy[2], int)\n            self.assertIsInstance(policy[3], int)\n            self.assertIn(policy[0], ["0tag", "1tag"])\n            self.assertIn(policy[1], ["3tag", "4tag"])\n            self.assertIn(policy[2], [0, 1])\n            self.assertIn(policy[3], [3, 4])\n            for i in [4, 5]:\n                self.assertIsInstance(policy[i], dict)\n                for key in ["const_factor", "int_factor", "float_factor", "id_factor"]:\n                    self.assertIn(key, policy[i])\n                self.assertIsInstance(policy[i]["float_factor"], float)\n                self.assertIsInstance(policy[i]["int_factor"], int)\n                self.assertIn(policy[i]["const_factor"], [3])\n                self.assertIn(policy[i]["int_factor"], [8, 10, 12])\n                self.assertIn(policy[i]["float_factor"], [2.4, 2, 1.6])\n                self.assertIn(policy[i]["id_factor"], [3, 4, 100])\n\n        pbt, runner = self.basicSetup(log_config=True, synch=True, step_once=False)\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: i}\n            self.on_trial_result(pbt, runner, trials[i], result(10, i))\n        log_files = ["pbt_global.txt", "pbt_policy_0.txt", "pbt_policy_1.txt"]\n        for log_file in log_files:\n            self.assertTrue(os.path.exists(os.path.join(tmpdir, log_file)))\n            raw_policy = open(os.path.join(tmpdir, log_file), "r").readlines()\n            for line in raw_policy:\n                check_policy(json.loads(line))\n        shutil.rmtree(tmpdir)\n\n    def testReplay(self):\n        # Returns unique increasing parameter mutations\n        class _Counter:\n            def __init__(self, start=0):\n                self.count = start - 1\n\n            def __call__(self, *args, **kwargs):\n                self.count += 1\n                return self.count\n\n        pbt, runner = self.basicSetup(\n            num_trials=4,\n            perturbation_interval=5,\n            log_config=True,\n            step_once=False,\n            synch=False,\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "int_factor": _Counter(1000),\n            },\n        )\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n\n        # Internal trial state to collect the real PBT history\n        class _TrialState:\n            def __init__(self, config):\n                self.step = 0\n                self.config = config\n                self.history = []\n\n            def forward(self, t):\n                while self.step < t:\n                    self.history.append(self.config)\n                    self.step += 1\n\n        trial_state = []\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: 0}\n            trial_state.append(_TrialState(trial.config))\n\n        # Helper function to simulate stepping trial k a number of steps,\n        # and reporting a score at the end\n        def trial_step(k, steps, score):\n            res = result(trial_state[k].step + steps, score)\n\n            trials[k].last_result = res\n            trial_state[k].forward(res[TRAINING_ITERATION])\n\n            old_config = trials[k].config\n            self.on_trial_result(pbt, runner, trials[k], res)\n            new_config = trials[k].config\n            trial_state[k].config = new_config.copy()\n\n            if old_config != new_config:\n                # Copy history from source trial\n                source = -1\n                for m, cand in enumerate(trials):\n                    if cand.trainable_name == trials[k].restored_checkpoint:\n                        source = m\n                        break\n                assert source >= 0\n                trial_state[k].history = trial_state[source].history.copy()\n                trial_state[k].step = trial_state[source].step\n\n        # Initial steps\n        trial_step(0, 10, 0)\n        trial_step(1, 11, 10)\n        trial_step(2, 12, 0)\n        trial_step(3, 13, 0)\n\n        # Next block\n        trial_step(0, 10, -10)  # 0 <-- 1, new_t=11\n        trial_step(2, 8, -20)  # 2 <-- 1, new_t=11\n        trial_step(3, 9, 0)\n        trial_step(1, 7, 0)\n\n        # Next block\n        trial_step(1, 12, 0)\n        trial_step(2, 13, 0)\n        trial_step(3, 14, 10)\n        trial_step(0, 11, 0)  # 0 <-- 3, new_t=13+9+14=36\n\n        # Next block\n        trial_step(0, 6, 20)\n        trial_step(3, 9, -40)  # 3 <-- 0, new_t=42\n        trial_step(2, 8, -50)  # 2 <-- 0, new_t=42\n        trial_step(1, 7, 30)\n        trial_step(2, 8, -60)  # 2 <-- 1, new_t=37\n\n        # Next block\n        trial_step(0, 10, 0)\n        trial_step(1, 10, 0)\n        trial_step(2, 10, 0)\n        trial_step(3, 10, 0)\n\n        # Playback trainable to collect configs at each step\n        class Playback(Trainable):\n            def setup(self, config):\n                self.config = config\n                self.replayed = []\n                self.iter = 0\n\n            def step(self):\n                self.iter += 1\n                self.replayed.append(self.config)\n                return {\n                    "reward": 0,\n                    "done": False,\n                    "replayed": self.replayed,\n                    TRAINING_ITERATION: self.iter,\n                }\n\n            def save_checkpoint(self, checkpoint_dir):\n                path = os.path.join(checkpoint_dir, "checkpoint")\n                with open(path, "w") as f:\n                    f.write(json.dumps({"iter": self.iter, "replayed": self.replayed}))\n                return path\n\n            def load_checkpoint(self, checkpoint_path):\n                with open(checkpoint_path) as f:\n                    checkpoint_json = json.loads(f.read())\n                    self.iter = checkpoint_json["iter"]\n                    self.replayed = checkpoint_json["replayed"]\n\n        # Loop through all trials and check if PBT history is the\n        # same as the playback history\n        for i, trial in enumerate(trials):\n            if trial.trial_id == "1":  # Did not exploit anything\n                continue\n\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trial.trial_id))\n            )\n            analysis = tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[i].step},\n            )\n\n            replayed = analysis.trials[0].last_result["replayed"]\n            self.assertSequenceEqual(trial_state[i].history, replayed)\n\n        # Trial 1 did not exploit anything and should raise an error\n        with self.assertRaises(ValueError):\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trials[1].trial_id))\n            )\n            tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[1].step},\n            )\n\n        shutil.rmtree(tmpdir)\n\n    def testReplaySynch(self):\n        # Returns unique increasing parameter mutations\n        class _Counter:\n            def __init__(self, start=0):\n                self.count = start - 1\n\n            def __call__(self, *args, **kwargs):\n                self.count += 1\n                return self.count\n\n        pbt, runner = self.basicSetup(\n            num_trials=4,\n            perturbation_interval=5,\n            log_config=True,\n            step_once=False,\n            synch=True,\n            hyperparam_mutations={\n                "float_factor": lambda: 100.0,\n                "int_factor": _Counter(1000),\n            },\n        )\n        trials = runner.get_trials()\n        tmpdir = tempfile.mkdtemp()\n\n        # Internal trial state to collect the real PBT history\n        class _TrialState:\n            def __init__(self, config):\n                self.step = 0\n                self.config = config\n                self.history = []\n\n            def forward(self, t):\n                while self.step < t:\n                    self.history.append(self.config)\n                    self.step += 1\n\n        trial_state = []\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {TRAINING_ITERATION: 0}\n            trial_state.append(_TrialState(trial.config))\n\n        # Helper function to simulate stepping trial k a number of steps,\n        # and reporting a score at the end\n        def trial_step(k, steps, score, synced=False):\n            res = result(trial_state[k].step + steps, score)\n\n            trials[k].last_result = res\n            trial_state[k].forward(res[TRAINING_ITERATION])\n\n            if not synced:\n                action = self.on_trial_result(pbt, runner, trials[k], res)\n                runner.process_action(trials[k], action)\n                return\n            else:\n                # Reached synchronization point\n                old_configs = [trial.config for trial in trials]\n                action = self.on_trial_result(pbt, runner, trials[k], res)\n                runner.process_action(trials[k], action)\n                new_configs = [trial.config for trial in trials]\n\n                for i in range(len(trials)):\n                    old_config = old_configs[i]\n                    new_config = new_configs[i]\n                    if old_config != new_config:\n                        # Copy history from source trial\n                        source = -1\n                        for m, cand in enumerate(trials):\n                            if cand.trainable_name == trials[i].restored_checkpoint:\n                                source = m\n                                break\n                        assert source >= 0\n                        trial_state[i].history = trial_state[source].history.copy()\n                        trial_state[i].step = trial_state[source].step\n                        trial_state[i].config = new_config.copy()\n\n        # Initial steps\n        trial_step(0, 10, 0)\n        trial_step(1, 11, 10)\n        trial_step(2, 12, 0)\n        trial_step(3, 13, -1, synced=True)\n\n        # 3 <-- 1, new_t 11\n        # next_perturb_sync = 13\n\n        # Next block\n        trial_step(0, 17, -10)  # 20\n        trial_step(2, 15, -20)  # 20\n        trial_step(3, 16, 0)  # 20\n        trial_step(1, 7, 1, synced=True)  # 18\n\n        # 2 <-- 1, new_t=11+7=18\n        # next_perturb_sync = 20\n\n        # Next block\n        trial_step(2, 13, 0)  # 31\n        trial_step(3, 14, 10)  # 34\n        trial_step(0, 11, -1)  # 31\n        trial_step(1, 12, 0, synced=True)  # 30\n\n        # 0 <-- 3, new_t=11+9+14=34\n        # next_perturb_sync = 34\n\n        # Next block\n        trial_step(0, 6, 20)  # 40\n        trial_step(3, 9, -40)  # 43\n        trial_step(2, 8, -50)  # 39\n        trial_step(1, 7, 30, synced=True)  # 37\n\n        # 2 <-- 1, new_t=18+13+8=37\n        # next_perturb_sync = 43\n\n        # Playback trainable to collect configs at each step\n        class Playback(Trainable):\n            def setup(self, config):\n                self.config = config\n                self.replayed = []\n                self.iter = 0\n\n            def step(self):\n                self.iter += 1\n                self.replayed.append(self.config)\n                return {\n                    "reward": 0,\n                    "done": False,\n                    "replayed": self.replayed,\n                    TRAINING_ITERATION: self.iter,\n                }\n\n            def save_checkpoint(self, checkpoint_dir):\n                path = os.path.join(checkpoint_dir, "checkpoint")\n                with open(path, "w") as f:\n                    f.write(json.dumps({"iter": self.iter, "replayed": self.replayed}))\n                return path\n\n            def load_checkpoint(self, checkpoint_path):\n                with open(checkpoint_path) as f:\n                    checkpoint_json = json.loads(f.read())\n                    self.iter = checkpoint_json["iter"]\n                    self.replayed = checkpoint_json["replayed"]\n\n        # Loop through all trials and check if PBT history is the\n        # same as the playback history\n        for i, trial in enumerate(trials):\n            if trial.trial_id in ["1"]:  # Did not exploit anything\n                continue\n\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trial.trial_id))\n            )\n            analysis = tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[i].step},\n            )\n\n            replayed = analysis.trials[0].last_result["replayed"]\n            self.assertSequenceEqual(trial_state[i].history, replayed)\n\n        # Trial 1 did not exploit anything and should raise an error\n        with self.assertRaises(ValueError):\n            replay = PopulationBasedTrainingReplay(\n                os.path.join(tmpdir, "pbt_policy_{}.txt".format(trials[1].trial_id))\n            )\n            tune.run(\n                Playback,\n                scheduler=replay,\n                stop={TRAINING_ITERATION: trial_state[1].step},\n            )\n\n        shutil.rmtree(tmpdir)\n\n    def testPostprocessingHook(self):\n        def explore(new_config):\n            new_config["id_factor"] = 42\n            new_config["float_factor"] = 43\n            return new_config\n\n        pbt, runner = self.basicSetup(resample_prob=0.0, explore=explore)\n        trials = runner.get_trials()\n        self.on_trial_result(\n            pbt, runner, trials[0], result(20, -100), TrialScheduler.PAUSE\n        )\n        self.assertEqual(trials[0].config["id_factor"], 42)\n        self.assertEqual(trials[0].config["float_factor"], 43)\n\n    def testFastPerturb(self):\n        pbt, runner = self.basicSetup(\n            perturbation_interval=1, step_once=False, log_config=True\n        )\n        trials = runner.get_trials()\n\n        tmpdir = tempfile.mkdtemp()\n        for i, trial in enumerate(trials):\n            trial.local_dir = tmpdir\n            trial.last_result = {}\n        self.on_trial_result(\n            pbt, runner, trials[1], result(1, 10), TrialScheduler.CONTINUE\n        )\n        self.on_trial_result(\n            pbt, runner, trials[2], result(1, 200), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(pbt._num_checkpoints, 1)\n\n        pbt._exploit(runner.trial_executor, trials[1], trials[2])\n        shutil.rmtree(tmpdir)\n\n    def testContextExit(self):\n        vals = [5, 1]\n\n        class MockContext:\n            def __init__(self, config):\n                self.config = config\n                self.active = False\n\n            def __enter__(self):\n                print("Set up resource.", self.config)\n                with open("status.txt", "wt") as fp:\n                    fp.write("Activate\\n")\n                self.active = True\n                return self\n\n            def __exit__(self, type, value, traceback):\n                print("Clean up resource.", self.config)\n                with open("status.txt", "at") as fp:\n                    fp.write("Cleanup\\n")\n                self.active = False\n\n        def train(config):\n            with MockContext(config):\n                for i in range(10):\n                    tune.report(metric=i + config["x"])\n\n        class MockScheduler(FIFOScheduler):\n            def on_trial_result(self, trial_runner, trial, result):\n                return TrialScheduler.STOP\n\n        scheduler = MockScheduler()\n\n        out = tune.run(train, config={"x": tune.grid_search(vals)}, scheduler=scheduler)\n\n        ever_active = set()\n        active = set()\n        for trial in out.trials:\n            with open(os.path.join(trial.logdir, "status.txt"), "rt") as fp:\n                status = fp.read()\n            print(f"Status for trial {trial}: {status}")\n            if "Activate" in status:\n                ever_active.add(trial)\n                active.add(trial)\n            if "Cleanup" in status:\n                active.remove(trial)\n\n        print(f"Ever active: {ever_active}")\n        print(f"Still active: {active}")\n\n        self.assertEqual(len(ever_active), len(vals))\n        self.assertEqual(len(active), 0)\n\n\nclass E2EPopulationBasedTestingSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=4)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def basicSetup(\n        self,\n        resample_prob=0.0,\n        explore=None,\n        perturbation_interval=10,\n        log_config=False,\n        hyperparams=None,\n        hyperparam_mutations=None,\n        step_once=True,\n    ):\n        hyperparam_mutations = hyperparam_mutations or {\n            "float_factor": lambda: 100.0,\n            "int_factor": lambda: 10,\n            "id_factor": [100],\n        }\n        pbt = PopulationBasedTraining(\n            metric="mean_accuracy",\n            mode="max",\n            time_attr="training_iteration",\n            perturbation_interval=perturbation_interval,\n            resample_probability=resample_prob,\n            quantile_fraction=0.25,\n            hyperparam_mutations=hyperparam_mutations,\n            custom_explore_fn=explore,\n            log_config=log_config,\n        )\n        return pbt\n\n    def testCheckpointing(self):\n        pbt = self.basicSetup(perturbation_interval=2)\n\n        class train(tune.Trainable):\n            def step(self):\n                return {"mean_accuracy": self.training_iteration}\n\n            def save_checkpoint(self, path):\n                checkpoint = os.path.join(path, "checkpoint")\n                with open(checkpoint, "w") as f:\n                    f.write("OK")\n                return checkpoint\n\n            def reset_config(self, config):\n                return True\n\n            def load_checkpoint(self, checkpoint):\n                pass\n\n        trial_hyperparams = {\n            "float_factor": 2.0,\n            "const_factor": 3,\n            "int_factor": 10,\n            "id_factor": 0,\n        }\n\n        analysis = tune.run(\n            train,\n            num_samples=3,\n            scheduler=pbt,\n            checkpoint_freq=3,\n            config=trial_hyperparams,\n            stop={"training_iteration": 30},\n        )\n\n        for trial in analysis.trials:\n            self.assertEqual(trial.status, Trial.TERMINATED)\n            self.assertTrue(trial.has_checkpoint())\n\n    def testCheckpointDict(self):\n        pbt = self.basicSetup(perturbation_interval=2)\n\n        class train_dict(tune.Trainable):\n            def setup(self, config):\n                self.state = {"hi": 1}\n\n            def step(self):\n                return {"mean_accuracy": self.training_iteration}\n\n            def save_checkpoint(self, path):\n                return self.state\n\n            def load_checkpoint(self, state):\n                self.state = state\n\n            def reset_config(self, config):\n                return True\n\n        trial_hyperparams = {\n            "float_factor": 2.0,\n            "const_factor": 3,\n            "int_factor": 10,\n            "id_factor": 0,\n        }\n\n        analysis = tune.run(\n            train_dict,\n            num_samples=3,\n            scheduler=pbt,\n            checkpoint_freq=3,\n            config=trial_hyperparams,\n            stop={"training_iteration": 30},\n        )\n\n        for trial in analysis.trials:\n            self.assertEqual(trial.status, Trial.TERMINATED)\n            self.assertTrue(trial.has_checkpoint())\n\n\nclass AsyncHyperBandSuite(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n        _register_all()  # re-register the evicted objects\n\n    def basicSetup(self, scheduler):\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        scheduler.on_trial_add(None, t1)\n        scheduler.on_trial_add(None, t2)\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t1, result(i, i * 100)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(5):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t2, result(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        return t1, t2\n\n    def nanSetup(self, scheduler):\n        t1 = Trial("PPO")  # mean is 450, max 450, t_max=10\n        t2 = Trial("PPO")  # mean is nan, max nan, t_max=10\n        scheduler.on_trial_add(None, t1)\n        scheduler.on_trial_add(None, t2)\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t1, result(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t2, result(i, np.nan)),\n                TrialScheduler.CONTINUE,\n            )\n        return t1, t2\n\n    def nanInfSetup(self, scheduler, runner=None):\n        t1 = Trial("PPO")\n        t2 = Trial("PPO")\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(runner, t1)\n        scheduler.on_trial_add(runner, t2)\n        scheduler.on_trial_add(runner, t3)\n        for i in range(10):\n            scheduler.on_trial_result(runner, t1, result(i, np.nan))\n        for i in range(10):\n            scheduler.on_trial_result(runner, t2, result(i, float("inf")))\n        for i in range(10):\n            scheduler.on_trial_result(runner, t3, result(i, float("-inf")))\n        return t1, t2, t3\n\n    def testAsyncHBOnComplete(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean", mode="max", max_t=10, brackets=1\n        )\n        t1, t2 = self.basicSetup(scheduler)\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        scheduler.on_trial_complete(None, t3, result(10, 1000))\n        self.assertEqual(\n            scheduler.on_trial_result(None, t2, result(101, 0)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBGracePeriod(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=2.5,\n            reduction_factor=3,\n            brackets=1,\n        )\n        t1, t2 = self.basicSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, 1000))\n        scheduler.on_trial_complete(None, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(1, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(2, 10)), TrialScheduler.CONTINUE\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(3, 10)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBAllCompletes(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean", mode="max", max_t=10, brackets=10\n        )\n        trials = [Trial("PPO") for i in range(10)]\n        for t in trials:\n            scheduler.on_trial_add(None, t)\n\n        for t in trials:\n            self.assertEqual(\n                scheduler.on_trial_result(None, t, result(10, -2)), TrialScheduler.STOP\n            )\n\n    def testAsyncHBUsesPercentile(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=1,\n            max_t=10,\n            reduction_factor=2,\n            brackets=1,\n        )\n        t1, t2 = self.basicSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, 1000))\n        scheduler.on_trial_complete(None, t2, result(10, 1000))\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(1, 260)), TrialScheduler.STOP\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(2, 260)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBNanPercentile(self):\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=1,\n            max_t=10,\n            reduction_factor=2,\n            brackets=1,\n        )\n        t1, t2 = self.nanSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, 450))\n        scheduler.on_trial_complete(None, t2, result(10, np.nan))\n        t3 = Trial("PPO")\n        scheduler.on_trial_add(None, t3)\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(1, 260)), TrialScheduler.STOP\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t3, result(2, 260)), TrialScheduler.STOP\n        )\n\n    def testAsyncHBSaveRestore(self):\n        _, tmpfile = tempfile.mkstemp()\n\n        scheduler = AsyncHyperBandScheduler(\n            metric="episode_reward_mean",\n            mode="max",\n            grace_period=1,\n            max_t=10,\n            reduction_factor=2,\n            brackets=1,\n        )\n\n        # Add some trials\n        trials = [Trial("PPO") for i in range(10)]\n        for t in trials:\n            scheduler.on_trial_add(None, t)\n\n        # Report some results\n        for t in trials[0:5]:\n            self.assertNotEqual(\n                scheduler.on_trial_result(None, t, result(1, 10)), TrialScheduler.STOP\n            )\n\n        # Report worse result: Trial should stop\n        self.assertEqual(\n            scheduler.on_trial_result(None, trials[5], result(1, 5)),\n            TrialScheduler.STOP,\n        )\n\n        scheduler.save(tmpfile)\n\n        scheduler2 = AsyncHyperBandScheduler()\n        scheduler2.restore(tmpfile)\n\n        # Report a new bad result: Trial should stop\n        self.assertEqual(\n            scheduler2.on_trial_result(None, trials[6], result(1, 4)),\n            TrialScheduler.STOP,\n        )\n\n        # Create a new trial and report bad result: Trial should stop\n        # Report a new bad result: Trial should stop\n        new_trial = Trial("PPO")\n        scheduler2.on_trial_add(None, new_trial)\n        self.assertEqual(\n            scheduler2.on_trial_result(None, new_trial, result(1, 2)),\n            TrialScheduler.STOP,\n        )\n\n    def testAsyncHBNonStopTrials(self):\n        trials = [Trial("PPO") for i in range(4)]\n        scheduler = AsyncHyperBandScheduler(\n            metric="metric",\n            mode="max",\n            grace_period=1,\n            max_t=3,\n            reduction_factor=2,\n            brackets=1,\n            stop_last_trials=False,\n        )\n        scheduler.on_trial_add(None, trials[0])\n        scheduler.on_trial_add(None, trials[1])\n        scheduler.on_trial_add(None, trials[2])\n        scheduler.on_trial_add(None, trials[3])\n\n        # Report one result\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 2, "metric": 10}\n        )\n        assert action == TrialScheduler.CONTINUE\n        action = scheduler.on_trial_result(\n            None, trials[1], {"training_iteration": 2, "metric": 8}\n        )\n        assert action == TrialScheduler.STOP\n        action = scheduler.on_trial_result(\n            None, trials[2], {"training_iteration": 2, "metric": 6}\n        )\n        assert action == TrialScheduler.STOP\n        action = scheduler.on_trial_result(\n            None, trials[3], {"training_iteration": 2, "metric": 4}\n        )\n        assert action == TrialScheduler.STOP\n\n        # Report more. This will fail if `stop_last_trials=True`\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 4, "metric": 10}\n        )\n        assert action == TrialScheduler.CONTINUE\n\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 8, "metric": 10}\n        )\n        assert action == TrialScheduler.CONTINUE\n\n        # Also continue if we fall below the cutoff eventually\n        action = scheduler.on_trial_result(\n            None, trials[0], {"training_iteration": 14, "metric": 1}\n        )\n        assert action == TrialScheduler.CONTINUE\n\n    def testMedianStoppingNanInf(self):\n        scheduler = MedianStoppingRule(metric="episode_reward_mean", mode="max")\n\n        t1, t2, t3 = self.nanInfSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, np.nan))\n        scheduler.on_trial_complete(None, t2, result(10, float("inf")))\n        scheduler.on_trial_complete(None, t3, result(10, float("-inf")))\n\n    def testHyperbandNanInf(self):\n        scheduler = HyperBandScheduler(metric="episode_reward_mean", mode="max")\n        t1, t2, t3 = self.nanInfSetup(scheduler)\n        scheduler.on_trial_complete(None, t1, result(10, np.nan))\n        scheduler.on_trial_complete(None, t2, result(10, float("inf")))\n        scheduler.on_trial_complete(None, t3, result(10, float("-inf")))\n\n    def testBOHBNanInf(self):\n        scheduler = HyperBandForBOHB(metric="episode_reward_mean", mode="max")\n\n        runner = _MockTrialRunner(scheduler)\n        runner._search_alg = MagicMock()\n        runner._search_alg.searcher = MagicMock()\n\n        t1, t2, t3 = self.nanInfSetup(scheduler, runner)\n        # skip trial complete in this mock setting\n\n    def testPBTNanInf(self):\n        scheduler = PopulationBasedTraining(metric="episode_reward_mean", mode="max")\n        t1, t2, t3 = self.nanInfSetup(scheduler, runner=MagicMock())\n        scheduler.on_trial_complete(None, t1, result(10, np.nan))\n        scheduler.on_trial_complete(None, t2, result(10, float("inf")))\n        scheduler.on_trial_complete(None, t3, result(10, float("-inf")))\n\n    def _test_metrics(self, result_func, metric, mode):\n        scheduler = AsyncHyperBandScheduler(\n            grace_period=1,\n            time_attr="training_iteration",\n            metric=metric,\n            mode=mode,\n            brackets=1,\n        )\n        t1 = Trial("PPO")  # mean is 450, max 900, t_max=10\n        t2 = Trial("PPO")  # mean is 450, max 450, t_max=5\n        scheduler.on_trial_add(None, t1)\n        scheduler.on_trial_add(None, t2)\n        for i in range(10):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t1, result_func(i, i * 100)),\n                TrialScheduler.CONTINUE,\n            )\n        for i in range(5):\n            self.assertEqual(\n                scheduler.on_trial_result(None, t2, result_func(i, 450)),\n                TrialScheduler.CONTINUE,\n            )\n        scheduler.on_trial_complete(None, t1, result_func(10, 1000))\n        self.assertEqual(\n            scheduler.on_trial_result(None, t2, result_func(5, 450)),\n            TrialScheduler.CONTINUE,\n        )\n        self.assertEqual(\n            scheduler.on_trial_result(None, t2, result_func(6, 0)),\n            TrialScheduler.CONTINUE,\n        )\n\n    def testAlternateMetrics(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, neg_mean_loss=rew)\n\n        self._test_metrics(result2, "neg_mean_loss", "max")\n\n    def testAlternateMetricsMin(self):\n        def result2(t, rew):\n            return dict(training_iteration=t, mean_loss=-rew)\n\n        self._test_metrics(result2, "mean_loss", "min")\n\n    def _testAnonymousMetricEndToEnd(self, scheduler_cls, searcher=None):\n        def train(config):\n            return config["value"]\n\n        out = tune.run(\n            train,\n            mode="max",\n            num_samples=1,\n            config={"value": tune.uniform(-2.0, 2.0)},\n            scheduler=scheduler_cls(),\n            search_alg=searcher,\n        )\n\n        self.assertTrue(bool(out.best_trial))\n\n    def testAnonymousMetricEndToEndFIFO(self):\n        self._testAnonymousMetricEndToEnd(FIFOScheduler)\n\n    def testAnonymousMetricEndToEndASHA(self):\n        self._testAnonymousMetricEndToEnd(AsyncHyperBandScheduler)\n\n    def testAnonymousMetricEndToEndBOHB(self):\n        from ray.tune.search.bohb import TuneBOHB\n\n        self._testAnonymousMetricEndToEnd(HyperBandForBOHB, TuneBOHB())\n\n    def testAnonymousMetricEndToEndMedian(self):\n        self._testAnonymousMetricEndToEnd(MedianStoppingRule)\n\n    def testAnonymousMetricEndToEndPBT(self):\n        self._testAnonymousMetricEndToEnd(PopulationBasedTraining)\n\n\nif __name__ == "__main__":\n    import pytest\n\n    sys.exit(pytest.main(["-v", __file__]))\n',
            'python/ray/tune/tests/test_trial_scheduler_pbt.py': 'import numpy as np\nimport os\nimport pickle\nimport random\nimport unittest\nimport sys\nimport time\nfrom unittest.mock import MagicMock\n\n\nimport ray\nfrom ray import tune\nfrom ray.air import Checkpoint\nfrom ray.air._internal.checkpoint_manager import _TrackedCheckpoint, CheckpointStorage\nfrom ray.air.config import FailureConfig, RunConfig, CheckpointConfig\nfrom ray.tune import Trainable\nfrom ray.tune.experiment import Trial\nfrom ray.tune.execution.trial_runner import TrialRunner\nfrom ray.tune.execution.ray_trial_executor import RayTrialExecutor\nfrom ray.tune.schedulers import PopulationBasedTraining\nfrom ray.tune.tune_config import TuneConfig\nfrom ray._private.test_utils import object_memory_usage\n\n\n# Import psutil after ray so the packaged version is used.\nimport psutil\n\nMB = 1024 ** 2\n\n\nclass MockParam(object):\n    def __init__(self, params):\n        self._params = params\n        self._index = 0\n\n    def __call__(self, *args, **kwargs):\n        val = self._params[self._index % len(self._params)]\n        self._index += 1\n        return val\n\n\nclass PopulationBasedTrainingMemoryTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=1, object_store_memory=100 * MB)\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testMemoryCheckpointFree(self):\n        class MyTrainable(Trainable):\n            def setup(self, config):\n                # Make sure this is large enough so ray uses object store\n                # instead of in-process store.\n                self.large_object = random.getrandbits(int(10e6))\n                self.iter = 0\n                self.a = config["a"]\n\n            def step(self):\n                self.iter += 1\n                return {"metric": self.iter + self.a}\n\n            def save_checkpoint(self, checkpoint_dir):\n                file_path = os.path.join(checkpoint_dir, "model.mock")\n\n                with open(file_path, "wb") as fp:\n                    pickle.dump((self.large_object, self.iter, self.a), fp)\n                return file_path\n\n            def load_checkpoint(self, path):\n                with open(path, "rb") as fp:\n                    self.large_object, self.iter, self.a = pickle.load(fp)\n\n        class CustomExecutor(RayTrialExecutor):\n            def save(self, *args, **kwargs):\n                checkpoint = super(CustomExecutor, self).save(*args, **kwargs)\n                assert object_memory_usage() <= (12 * 80e6)\n                return checkpoint\n\n        param_a = MockParam([1, -1])\n\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="metric",\n            mode="max",\n            perturbation_interval=1,\n            hyperparam_mutations={"b": [-1]},\n        )\n\n        tune.run(\n            MyTrainable,\n            name="ray_demo",\n            scheduler=pbt,\n            stop={"training_iteration": 10},\n            num_samples=3,\n            checkpoint_freq=1,\n            fail_fast=True,\n            config={"a": tune.sample_from(lambda _: param_a())},\n            trial_executor=CustomExecutor(reuse_actors=False),\n        )\n\n\nclass PopulationBasedTrainingFileDescriptorTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n        os.environ["TUNE_GLOBAL_CHECKPOINT_S"] = "0"\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testFileFree(self):\n        class MyTrainable(Trainable):\n            def setup(self, config):\n                self.iter = 0\n                self.a = config["a"]\n\n            def step(self):\n                self.iter += 1\n                return {"metric": self.iter + self.a}\n\n            def save_checkpoint(self, checkpoint_dir):\n                file_path = os.path.join(checkpoint_dir, "model.mock")\n\n                with open(file_path, "wb") as fp:\n                    pickle.dump((self.iter, self.a), fp)\n                return file_path\n\n            def load_checkpoint(self, path):\n                with open(path, "rb") as fp:\n                    self.iter, self.a = pickle.load(fp)\n\n        from ray.tune.callback import Callback\n\n        class FileCheck(Callback):\n            def __init__(self, verbose=False):\n                self.iter_ = 0\n                self.process = psutil.Process()\n                self.verbose = verbose\n\n            def on_trial_result(self, *args, **kwargs):\n                self.iter_ += 1\n                all_files = self.process.open_files()\n                if self.verbose:\n                    print("Iteration", self.iter_)\n                    print("=" * 10)\n                    print("Object memory use: ", object_memory_usage())\n                    print("Virtual Mem:", self.get_virt_mem() >> 30, "gb")\n                    print("File Descriptors:", len(all_files))\n                assert len(all_files) < 20\n\n            @classmethod\n            def get_virt_mem(cls):\n                return psutil.virtual_memory().used\n\n        param_a = MockParam([1, -1])\n\n        pbt = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="metric",\n            mode="max",\n            perturbation_interval=1,\n            quantile_fraction=0.5,\n            hyperparam_mutations={"b": [-1]},\n        )\n\n        tune.run(\n            MyTrainable,\n            name="ray_demo",\n            scheduler=pbt,\n            stop={"training_iteration": 10},\n            num_samples=4,\n            checkpoint_freq=2,\n            keep_checkpoints_num=1,\n            verbose=False,\n            fail_fast=True,\n            config={"a": tune.sample_from(lambda _: param_a())},\n            callbacks=[FileCheck()],\n        )\n\n\nclass PopulationBasedTrainingSynchTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n        def MockTrainingFuncSync(config, checkpoint_dir=None):\n            iter = 0\n\n            if checkpoint_dir:\n                checkpoint_path = os.path.join(checkpoint_dir, "checkpoint")\n                with open(checkpoint_path, "rb") as fp:\n                    a, iter = pickle.load(fp)\n\n            a = config["a"]  # Use the new hyperparameter if perturbed.\n\n            while True:\n                iter += 1\n                with tune.checkpoint_dir(step=iter) as checkpoint_dir:\n                    checkpoint_path = os.path.join(checkpoint_dir, "checkpoint")\n                    with open(checkpoint_path, "wb") as fp:\n                        pickle.dump((a, iter), fp)\n                # Different sleep times so that asynch test runs do not\n                # randomly succeed. If well performing trials finish later,\n                # then bad performing trials will already have continued\n                # to train, which is exactly what we want to test when\n                # comparing sync vs. async.\n                time.sleep(a / 20)\n                # Score gets better every iteration.\n                tune.report(mean_accuracy=iter + a, a=a)\n\n        self.MockTrainingFuncSync = MockTrainingFuncSync\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def synchSetup(self, synch, param=None):\n        if param is None:\n            param = [10, 20, 40]\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            log_config=True,\n            hyperparam_mutations={"c": lambda: 1},\n            synch=synch,\n        )\n\n        param_a = MockParam(param)\n\n        random.seed(100)\n        np.random.seed(100)\n        analysis = tune.run(\n            self.MockTrainingFuncSync,\n            config={"a": tune.sample_from(lambda _: param_a()), "c": 1},\n            fail_fast=True,\n            num_samples=3,\n            scheduler=scheduler,\n            name="testPBTSync",\n            stop={"training_iteration": 3},\n        )\n        return analysis\n\n    def testAsynchFail(self):\n        analysis = self.synchSetup(False)\n        self.assertTrue(\n            any(\n                analysis.dataframe(metric="mean_accuracy", mode="max")["mean_accuracy"]\n                != 43\n            )\n        )\n\n    def testSynchPass(self):\n        analysis = self.synchSetup(True)\n        self.assertTrue(\n            all(\n                analysis.dataframe(metric="mean_accuracy", mode="max")["mean_accuracy"]\n                == 43\n            )\n        )\n\n    def testSynchPassLast(self):\n        analysis = self.synchSetup(True, param=[30, 20, 10])\n        self.assertTrue(\n            all(\n                analysis.dataframe(metric="mean_accuracy", mode="max")["mean_accuracy"]\n                == 33\n            )\n        )\n\n    def testExploitWhileSavingTrial(self):\n        """Tests a synch PBT failure mode where a trial misses its `SAVING_RESULT` event\n        book-keeping due to being stopped by the PBT algorithm (to exploit another\n        trial).\n\n        Trials checkpoint ever N iterations, and the perturbation interval is every N\n        iterations. (N = 2 in the test.)\n\n        Raises a `TimeoutError` if hanging for a specified `timeout`.\n\n        1. Trial 0 comes in with training result\n        2. Trial 0 begins saving checkpoint (which may take a long time, 5s here)\n        3. Trial 1 comes in with result\n        4. Trial 1 forcefully stops Trial 0 via exploit, while trial_0.is_saving\n        5. Trial 0 should resume training properly with Trial 1\'s checkpoint\n        """\n\n        class MockTrainable(tune.Trainable):\n            def setup(self, config):\n                self.reset_config(config)\n\n            def step(self):\n                time.sleep(self.training_time)\n                return {"score": self.score}\n\n            def save_checkpoint(self, checkpoint_dir):\n                checkpoint = Checkpoint.from_dict({"a": self.a})\n                checkpoint_path = checkpoint.to_directory(path=checkpoint_dir)\n                time.sleep(self.saving_time)\n                return checkpoint_path\n\n            def load_checkpoint(self, checkpoint_dir):\n                checkpoint_dict = Checkpoint.from_directory(checkpoint_dir).to_dict()\n                self.a = checkpoint_dict["a"]\n\n            def reset_config(self, new_config):\n                self.a = new_config["a"]\n                self.score = new_config["score"]\n                self.training_time = new_config["training_time"]\n                self.saving_time = new_config["saving_time"]\n                return True\n\n        perturbation_interval = 2\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="score",\n            mode="max",\n            perturbation_interval=perturbation_interval,\n            hyperparam_mutations={\n                "a": tune.uniform(0, 1),\n            },\n            synch=True,\n        )\n\n        class TimeoutExceptionStopper(tune.stopper.TimeoutStopper):\n            def stop_all(self):\n                decision = super().stop_all()\n                if decision:\n                    raise TimeoutError("Trials are hanging! Timeout reached...")\n                return decision\n\n        timeout = 30.0\n        training_times = [0.1, 0.15]\n        saving_times = [5.0, 0.1]\n        tuner = tune.Tuner(\n            MockTrainable,\n            param_space={\n                "a": tune.uniform(0, 1),\n                "score": tune.grid_search([0, 1]),\n                "training_time": tune.sample_from(\n                    lambda spec: training_times[spec.config["score"]]\n                ),\n                "saving_time": tune.sample_from(\n                    lambda spec: saving_times[spec.config["score"]]\n                ),\n            },\n            tune_config=TuneConfig(\n                num_samples=1,\n                scheduler=scheduler,\n            ),\n            run_config=RunConfig(\n                stop=tune.stopper.CombinedStopper(\n                    tune.stopper.MaximumIterationStopper(5),\n                    TimeoutExceptionStopper(timeout),\n                ),\n                failure_config=FailureConfig(fail_fast=True),\n                checkpoint_config=CheckpointConfig(\n                    # Match `checkpoint_interval` with `perturbation_interval`\n                    checkpoint_frequency=perturbation_interval,\n                ),\n            ),\n        )\n        random.seed(100)\n        np.random.seed(1000)\n        tuner.fit()\n\n\nclass PopulationBasedTrainingConfigTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testNoConfig(self):\n        def MockTrainingFunc(config):\n            a = config["a"]\n            b = config["b"]\n            c1 = config["c"]["c1"]\n            c2 = config["c"]["c2"]\n\n            while True:\n                tune.report(mean_accuracy=a * b * (c1 + c2))\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            hyperparam_mutations={\n                "a": tune.uniform(0, 0.3),\n                "b": [1, 2, 3],\n                "c": {\n                    "c1": lambda: np.random.uniform(0.5),\n                    "c2": tune.choice([2, 3, 4]),\n                },\n            },\n        )\n\n        tune.run(\n            MockTrainingFunc,\n            fail_fast=True,\n            num_samples=4,\n            scheduler=scheduler,\n            name="testNoConfig",\n            stop={"training_iteration": 3},\n        )\n\n\nclass PopulationBasedTrainingResumeTest(unittest.TestCase):\n    def setUp(self):\n        ray.init(num_cpus=2)\n\n    def tearDown(self):\n        ray.shutdown()\n\n    def testPermutationContinuation(self):\n        """\n        Tests continuation of runs after permutation.\n        Sometimes, runs were continued from deleted checkpoints.\n        This deterministic initialisation would fail when the\n        fix was not applied.\n        See issues #9036, #9036\n        """\n\n        class MockTrainable(tune.Trainable):\n            def setup(self, config):\n                self.iter = 0\n                self.a = config["a"]\n                self.b = config["b"]\n                self.c = config["c"]\n\n            def step(self):\n                self.iter += 1\n                return {"mean_accuracy": (self.a - self.iter) * self.b}\n\n            def save_checkpoint(self, tmp_checkpoint_dir):\n                checkpoint_path = os.path.join(tmp_checkpoint_dir, "model.mock")\n                with open(checkpoint_path, "wb") as fp:\n                    pickle.dump((self.a, self.b, self.iter), fp)\n                return tmp_checkpoint_dir\n\n            def load_checkpoint(self, tmp_checkpoint_dir):\n                checkpoint_path = os.path.join(tmp_checkpoint_dir, "model.mock")\n                with open(checkpoint_path, "rb") as fp:\n                    self.a, self.b, self.iter = pickle.load(fp)\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            log_config=True,\n            hyperparam_mutations={"c": lambda: 1},\n        )\n\n        param_a = MockParam([10, 20, 30, 40])\n        param_b = MockParam([1.2, 0.9, 1.1, 0.8])\n\n        random.seed(100)\n        np.random.seed(1000)\n        tune.run(\n            MockTrainable,\n            config={\n                "a": tune.sample_from(lambda _: param_a()),\n                "b": tune.sample_from(lambda _: param_b()),\n                "c": 1,\n            },\n            fail_fast=True,\n            num_samples=4,\n            checkpoint_freq=1,\n            checkpoint_at_end=True,\n            keep_checkpoints_num=1,\n            checkpoint_score_attr="min-training_iteration",\n            scheduler=scheduler,\n            name="testPermutationContinuation",\n            stop={"training_iteration": 3},\n        )\n\n    def testPermutationContinuationFunc(self):\n        def MockTrainingFunc(config, checkpoint_dir=None):\n            iter = 0\n            a = config["a"]\n            b = config["b"]\n\n            if checkpoint_dir:\n                checkpoint_path = os.path.join(checkpoint_dir, "model.mock")\n                with open(checkpoint_path, "rb") as fp:\n                    a, b, iter = pickle.load(fp)\n\n            while True:\n                iter += 1\n                with tune.checkpoint_dir(step=iter) as checkpoint_dir:\n                    checkpoint_path = os.path.join(checkpoint_dir, "model.mock")\n                    with open(checkpoint_path, "wb") as fp:\n                        pickle.dump((a, b, iter), fp)\n                tune.report(mean_accuracy=(a - iter) * b)\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="mean_accuracy",\n            mode="max",\n            perturbation_interval=1,\n            log_config=True,\n            hyperparam_mutations={"c": lambda: 1},\n        )\n        param_a = MockParam([10, 20, 30, 40])\n        param_b = MockParam([1.2, 0.9, 1.1, 0.8])\n        random.seed(100)\n        np.random.seed(1000)\n        tune.run(\n            MockTrainingFunc,\n            config={\n                "a": tune.sample_from(lambda _: param_a()),\n                "b": tune.sample_from(lambda _: param_b()),\n                "c": 1,\n            },\n            fail_fast=True,\n            num_samples=4,\n            keep_checkpoints_num=1,\n            checkpoint_score_attr="min-training_iteration",\n            scheduler=scheduler,\n            name="testPermutationContinuationFunc",\n            stop={"training_iteration": 3},\n        )\n\n    def testBurnInPeriod(self):\n        runner = TrialRunner(trial_executor=MagicMock())\n\n        scheduler = PopulationBasedTraining(\n            time_attr="training_iteration",\n            metric="error",\n            mode="min",\n            perturbation_interval=5,\n            burn_in_period=50,\n            log_config=True,\n            synch=True,\n        )\n\n        class MockTrial(Trial):\n            @property\n            def checkpoint(self):\n                return _TrackedCheckpoint(\n                    dir_or_data={"data": "None"},\n                    storage_mode=CheckpointStorage.MEMORY,\n                    metrics={},\n                )\n\n            @property\n            def status(self):\n                return Trial.PAUSED\n\n            @status.setter\n            def status(self, status):\n                pass\n\n        trial1 = MockTrial("PPO", config=dict(num=1))\n        trial2 = MockTrial("PPO", config=dict(num=2))\n        trial3 = MockTrial("PPO", config=dict(num=3))\n        trial4 = MockTrial("PPO", config=dict(num=4))\n\n        runner.add_trial(trial1)\n        runner.add_trial(trial2)\n        runner.add_trial(trial3)\n        runner.add_trial(trial4)\n\n        scheduler.on_trial_add(runner, trial1)\n        scheduler.on_trial_add(runner, trial2)\n        scheduler.on_trial_add(runner, trial3)\n        scheduler.on_trial_add(runner, trial4)\n\n        # Add initial results.\n        scheduler.on_trial_result(\n            runner, trial1, result=dict(training_iteration=1, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial2, result=dict(training_iteration=1, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial3, result=dict(training_iteration=1, error=10)\n        )\n        scheduler.on_trial_result(\n            runner, trial4, result=dict(training_iteration=1, error=100)\n        )\n\n        # Add more results. Without burn-in, this would now exploit\n        scheduler.on_trial_result(\n            runner, trial1, result=dict(training_iteration=30, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial2, result=dict(training_iteration=30, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial3, result=dict(training_iteration=30, error=10)\n        )\n        scheduler.on_trial_result(\n            runner, trial4, result=dict(training_iteration=30, error=100)\n        )\n\n        self.assertEqual(trial4.config["num"], 4)\n\n        # Add more results. Since this is after burn-in, it should now exploit\n        scheduler.on_trial_result(\n            runner, trial1, result=dict(training_iteration=50, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial2, result=dict(training_iteration=50, error=50)\n        )\n        scheduler.on_trial_result(\n            runner, trial3, result=dict(training_iteration=50, error=10)\n        )\n        scheduler.on_trial_result(\n            runner, trial4, result=dict(training_iteration=50, error=100)\n        )\n\n        self.assertEqual(trial4.config["num"], 3)\n\n        # Assert that trials do not hang after `burn_in_period`\n        self.assertTrue(all(t.status == "PAUSED" for t in runner.get_trials()))\n        self.assertTrue(scheduler.choose_trial_to_run(runner))\n\n        # Assert that trials do not hang when a terminated trial is added\n        trial5 = Trial("PPO", config=dict(num=5))\n        runner.add_trial(trial5)\n        scheduler.on_trial_add(runner, trial5)\n        trial5.set_status(Trial.TERMINATED)\n        self.assertTrue(scheduler.choose_trial_to_run(runner))\n\n\nclass PopulationBasedTrainingLoggingTest(unittest.TestCase):\n    def testSummarizeHyperparamChanges(self):\n        class DummyTrial:\n            def __init__(self, config):\n                self.config = config\n\n        def test_config(\n            hyperparam_mutations,\n            old_config,\n            resample_probability=0.25,\n            print_summary=False,\n        ):\n            scheduler = PopulationBasedTraining(\n                time_attr="training_iteration",\n                hyperparam_mutations=hyperparam_mutations,\n                resample_probability=resample_probability,\n            )\n            new_config, operations = scheduler._get_new_config(\n                None, DummyTrial(old_config)\n            )\n            summary = scheduler._summarize_hyperparam_changes(\n                old_config, new_config, operations\n            )\n            if print_summary:\n                print(summary)\n            return scheduler, new_config, operations\n\n        # 1. Empty (no hyperparams mutated)\n        _, new_config, operations = test_config({}, {})\n        assert not new_config and not operations\n\n        # 2. No nesting\n        hyperparam_mutations = {\n            "a": tune.uniform(0, 1),\n            "b": list(range(5)),\n        }\n        scheduler, new_config, operations = test_config(\n            hyperparam_mutations, {"a": 0.5, "b": 2}\n        )\n        assert operations["a"] in [\n            f"* {factor}" for factor in scheduler._perturbation_factors\n        ] + ["resample"]\n        assert operations["b"] in ["shift left", "shift right", "resample"]\n\n        # 3. With nesting\n        hyperparam_mutations = {\n            "a": tune.uniform(0, 1),\n            "b": list(range(5)),\n            "c": {\n                "d": tune.uniform(2, 3),\n                "e": {"f": [-1, 0, 1]},\n            },\n        }\n        scheduler, new_config, operations = test_config(\n            hyperparam_mutations,\n            {\n                "a": 0.5,\n                "b": 2,\n                "c": {\n                    "d": 2.5,\n                    "e": {"f": 0},\n                },\n            },\n        )\n        assert isinstance(operations["c"], dict)\n        assert isinstance(operations["c"]["e"], dict)\n        assert operations["c"]["d"] in [\n            f"* {factor}" for factor in scheduler._perturbation_factors\n        ] + ["resample"]\n        assert operations["c"]["e"]["f"] in ["shift left", "shift right", "resample"]\n\n        # 4. Test shift that results in noop\n        hyperparam_mutations = {"a": [1]}\n        scheduler, new_config, operations = test_config(\n            hyperparam_mutations, {"a": 1}, resample_probability=0\n        )\n        assert operations["a"] in ["shift left (noop)", "shift right (noop)"]\n\n        # 5. Test that missing keys in inputs raises an error\n        with self.assertRaises(AssertionError):\n            scheduler._summarize_hyperparam_changes(\n                {"a": 1, "b": {"c": 2}},\n                {"a": 1, "b": {}},\n                {"a": "noop", "b": {"c": "noop"}},\n            )\n        with self.assertRaises(AssertionError):\n            scheduler._summarize_hyperparam_changes(\n                {"a": 1, "b": {"c": 2}}, {"a": 1, "b": {"c": 2}}, {"a": "noop"}\n            )\n\n\nif __name__ == "__main__":\n    import pytest\n\n    sys.exit(pytest.main(["-v", __file__]))\n',
        }
